window.ASBAB_NUZUL_CACHE["19"] = {"asbab_nuzul":{"64":[{"ar":"عَنِ ابْنِ عَبَّاسٍ رضي الله عنهما قَالَ: قَالَ رَسُولُ اللّهِ ﷺ لِجِبْرِيلَ: « أَلَا تَزُورُنَا أَكْثَرَ مِمَّا تَزُورُنَا؟ » قَالَ فَنَزَلَتْ { وَمَا نَتَنَزَّلُ إِلَّا بِأَمْرِ رَبِّكَ ۖ لَهُۥ مَا بَيْنَ أَيْدِينَا وَمَا خَلْفَنَا } الْآيَةَ. واللفظ للبخاري.","id":""}],"77":[{"ar":"عَنْ خَبَّابٍ رضي الله عنه قَالَ: كُنْتُ قَيْناً فِي الْجَاهِلِيَّةِ، وَكَانَ لِي عَلَى الْعَاصِ بْنِ وَائِلٍ دَيْنٌ، فَأَتَيْتُهُ أَتَقَاضَاهُ، قَالَ: لَا أُعْطِيكَ حَتَّى تَكْفُرَ بِمُحَمَّدٍ ﷺ، فَقُلْتُ: لَا أَكْفُرُ حَتَّى يُمِيتَكَ اللهُ ثُمَّ تُبْعَثَ، قَالَ: دَعْنِي حَتَّى أَمُوتَ وَأَبْعَثَ، فَسَأُوتَى مَالًا وَوَلَداً فَأَقْضِيكَ. فَنَزَلَتْ { أَفَرَءَيْتَ ٱلَّذِى كَفَرَ بِـَٔايَـٰتِنَا وَقَالَ لَأُوتَيَنَّ مَالًا وَوَلَدًا ﴿٧٧﴾ أَطَّلَعَ ٱلْغَيْبَ أَمِ ٱتَّخَذَ عِندَ ٱلرَّحْمَـٰنِ عَهْدًا ﴿٧٨﴾ }. واللفظ للبخاري.","id":""}],"78":[{"ar":"عَنْ خَبَّابٍ رضي الله عنه قَالَ: كُنْتُ قَيْناً فِي الْجَاهِلِيَّةِ، وَكَانَ لِي عَلَى الْعَاصِ بْنِ وَائِلٍ دَيْنٌ، فَأَتَيْتُهُ أَتَقَاضَاهُ، قَالَ: لَا أُعْطِيكَ حَتَّى تَكْفُرَ بِمُحَمَّدٍ ﷺ، فَقُلْتُ: لَا أَكْفُرُ حَتَّى يُمِيتَكَ اللهُ ثُمَّ تُبْعَثَ، قَالَ: دَعْنِي حَتَّى أَمُوتَ وَأَبْعَثَ، فَسَأُوتَى مَالًا وَوَلَداً فَأَقْضِيكَ. فَنَزَلَتْ { أَفَرَءَيْتَ ٱلَّذِى كَفَرَ بِـَٔايَـٰتِنَا وَقَالَ لَأُوتَيَنَّ مَالًا وَوَلَدًا ﴿٧٧﴾ أَطَّلَعَ ٱلْغَيْبَ أَمِ ٱتَّخَذَ عِندَ ٱلرَّحْمَـٰنِ عَهْدًا ﴿٧٨﴾ }. واللفظ للبخاري.","id":""}]},"mapping_ayat":{"19:21":[{"p":"Bukhari","n":732,"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنَا أَيُّوبُ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَقَرَأَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيمَا أُمِرَ وَسَكَتَ فِيمَا أُمِرَ{ وَمَا كَانَ رَبُّكَ نَسِيًّا }{ لَقَدْ كَانَ لَكُمْ فِي رَسُولِ اللَّهِ أُسْوَةٌ حَسَنَةٌ }","trj":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Isma'il] berkata, telah menceritakan kepada kami [Ayyub] dari ['Ikrimah] dari [Ibnu 'Abbas] berkata, \"Nabi shallallahu 'alaihi wasallam membaca (dengan suara dikeraskan) sesuai apa yang diperintahkan dan juga diam (tidak mengeraskan) sesuai apa yang diperintahkan '(Dan tidaklah Rabbmu lupa) ' (Qs. Maryam: 64). '(Sesungguhnya telah ada pada diri Rasulullah itu suri teladan yang baik bagimu) ' (Qs. Al Ahzab: 21)."}],"19:49":[{"p":"Bukhari","n":1949,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ شُعْبَةَ عَنْ سُلَيْمَانَ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ عَنْ خَبَّابٍ قَالَكُنْتُ قَيْنًا فِي الْجَاهِلِيَّةِ وَكَانَ لِي عَلَى الْعَاصِ بْنِ وَائِلٍ دَيْنٌ فَأَتَيْتُهُ أَتَقَاضَاهُ قَالَ لَا أُعْطِيكَ حَتَّى تَكْفُرَ بِمُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ لَا أَكْفُرُ حَتَّى يُمِيتَكَ اللَّهُ ثُمَّ تُبْعَثَ قَالَ دَعْنِي حَتَّى أَمُوتَ وَأُبْعَثَ فَسَأُوتَى مَالًا وَوَلَدًا فَأَقْضِيكَ فَنَزَلَتْ{ أَفَرَأَيْتَ الَّذِي كَفَرَ بِآيَاتِنَا وَقَالَ لَأُوتَيَنَّ مَالًا وَوَلَدًا أَطَّلَعَ الْغَيْبَ أَمْ اتَّخَذَ عِنْدَ الرَّحْمَنِ عَهْدًا }","trj":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Ibnu Abu 'Adiy] dari [Syu'bah] dari [Sulaiman] dari [Abu Adh-Dhuha] dari [Masruq] dari [Khabbab] berkata: \"Pada masa Jahiliyyah aku adalah seorang tukang besi dan emas dan Al 'Ash bin Wa'il pernah punya hutang kepadaku lalu aku datang menemuinya untuk menagihnya. Dia berkata: \"Aku tidak akan bayar kecuali kamu mau mengingkari (kufur) Muhammad shallallahu 'alaihi wasallam \". Aku katakan: \"Aku tidak akan kufur sampai kamu dimatikan oleh Allah Ta'ala lalu kamu dibangkitkan. Dia berkata: \"Biarkanlah aku sampai aku mati lalu dibangkitkan dan aku diberikan harta dan anak lalu aku bayar hutangku kepadamu\". Maka turunlah QS Maryam ayat 49 yang artinya: (\" Maka apakah kamu telah melihat orang yang kafir kepada ayat-ayat kami dan ia mengatakan: \"Pasti Aku akan diberi harta dan anak\". Adakah ia melihat yang ghaib atau ia telah membuat perjanjian di sisi Tuhan yang Maha Pemurah?\")."}],"19:64":[{"p":"Bukhari","n":732,"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنَا أَيُّوبُ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَقَرَأَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيمَا أُمِرَ وَسَكَتَ فِيمَا أُمِرَ{ وَمَا كَانَ رَبُّكَ نَسِيًّا }{ لَقَدْ كَانَ لَكُمْ فِي رَسُولِ اللَّهِ أُسْوَةٌ حَسَنَةٌ }","trj":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Isma'il] berkata, telah menceritakan kepada kami [Ayyub] dari ['Ikrimah] dari [Ibnu 'Abbas] berkata, \"Nabi shallallahu 'alaihi wasallam membaca (dengan suara dikeraskan) sesuai apa yang diperintahkan dan juga diam (tidak mengeraskan) sesuai apa yang diperintahkan '(Dan tidaklah Rabbmu lupa) ' (Qs. Maryam: 64). '(Sesungguhnya telah ada pada diri Rasulullah itu suri teladan yang baik bagimu) ' (Qs. Al Ahzab: 21)."},{"p":"Bukhari","n":6546,"ar":"حَدَّثَنَا خَلَّادُ بْنُ يَحْيَى حَدَّثَنَا عُمَرُ بْنُ ذَرٍّ سَمِعْتُ أَبِي يُحَدِّثُ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَا جِبْرِيلُ مَا يَمْنَعُكَ أَنْ تَزُورَنَا أَكْثَرَ مِمَّا تَزُورُنَا فَنَزَلَتْ{ وَمَا نَتَنَزَّلُ إِلَّا بِأَمْرِ رَبِّكَ لَهُ مَا بَيْنَ أَيْدِينَا وَمَا خَلْفَنَا }إِلَى آخِرِ الْآيَةِ قَالَ كَانَ هَذَا الْجَوَابَ لِمُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","trj":"Telah menceritakan kepada kami [Khallad bin Yahya] telah menceritakan kepada kami [Umar bin Dzar] aku mendengar [Ayahku] menceritakan dari [Said bin Jubair] dari [Ibn Abbas] Radliyallahu'anhuma, bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Wahai Jibril, apa yang menghalangimu untuk mengunjungi kami lebih sering daripada apa yang telah engkau lakukan?\" Maka turunlah ayat: '(Dan tidaklah Kami menurunkan ayat melainkan dengan perintah Tuhanmu, milik Dialah apa yang didepan kami dan di belakang kami) ', hingga akhir ayat (Qs. Maryam: 64). Dan jawaban ini adalah untuk Muhammad shallallahu 'alaihi wasallam.\""}],"19:71":[{"p":"Ahmad","n":3885,"ar":"حَدَّثَنَا ابْنُ إِدْرِيسَ قَالَ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرٍ عَنْ أُمِّ مُبَشِّرٍ امْرَأَةِ زَيْدِ بْنِ حَارِثَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَيْتِ حَفْصَةَ فَقَالَ لَا يَدْخُلُ النَّارَ أَحَدٌ شَهِدَ بَدْرًا وَالْحُدَيْبِيَةَ قَالَتْ حَفْصَةُ أَلَيْسَ اللَّهُ عَزَّ وَجَلَّ يَقُولُ{ وَإِنْ مِنْكُمْ إِلَّا وَارِدُهَا }قَالَتْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَهْ{ ثُمَّ نُنَجِّي الَّذِينَ اتَّقَوْا }","trj":"Telah menceritakan kepada kami [Ibnu Idris] berkata, telah menceritakan kepada kami [Al A'masy] dari [Abu Sufyan] dari [Jabir] dari [Ummu Mubasyir] isteri Zaid bin Haritsah, ia berkata, \"Saat Rasulullah shallallahu 'alaihi wasallam berada di rumah Hafshah, beliau bersabda: \"Tidak akan masuk neraka seseorang yang mengikuti perang Badar dan Hudaibiyah.\" Hafshah berkata, \"Bukankah Allah Azza Wa Jalla berfirman: '(Dan tidak ada seorangpun dari padamu, melainkan mendatangi neraka itu) ' (Qs. Maryam: 71). Rasulullah shallallahu 'alaihi wasallam lalu bersabda: \"Lalu bagaimana dengan firman Allah Ta'ala: '(Kemudian kami akan menyelamatkan orang-orang yang bertakwa) ' (Qs. Maryam: 72)."},{"p":"Ahmad","n":4148,"ar":"حَدَّثَنَا حَجَّاجٌ قَالَ أَخْبَرَنِي ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي أَبُو الزُّبَيْرِ أَنَّهُ سَمِعَ جَابِرًا قَالَ حَدَّثَتْنِي أُمُّ مُبَشِّرٍ أَنَّهاسَمِعَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِنْدَ حَفْصَةَ يَقُولُ لَا يَدْخُلُ النَّارَ إِنْ شَاءَ اللَّهُ مِنْ أَصْحَابِ الشَّجَرَةِ أَحَدٌ الَّذِينَ بَايَعُوا تَحْتَهَا فَقَالَتْ بَلَى يَا رَسُولَ اللَّهِ فَانْتَهَرَهَا فَقَالَتْ حَفْصَةُ{ وَإِنْ مِنْكُمْ إِلَّا وَارِدُهَا }فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ قَالَ اللَّهُ عَزَّ وَجَلَّ{ ثُمَّ نُنَجِّي الَّذِينَ اتَّقَوْا وَنَذَرُ الظَّالِمِينَ فِيهَا جِثِيًّا }","trj":"Telah menceritakan kepada kami [Hajjaj] dia berkata, telah mengabarkan kepadaku [Ibnu Juraij] berkata; telah mengabarkan kepadaku [Abu Zubair] bahwa dia mendengar [Jabir] berkata, telah menceritakan kepadaku [Ummu Mubasyir] bahwa dia mendengar Rasulullah shallallahu 'alaihi wasallam waktu berada di samping Hafshah, beliau bersabda: \"Insyaallah tidak akan masuk Neraka orang-orang yang pernah berbaiat di bawah pohon.\" Hafshah berkata, \"Tentu wahai Rasulullah, \" namun beliau menghardiknya hingga Hafshah pun membaca: '(Dan tidak ada seorang pun dari padamu, melainkan mendatangi neraka itu) ' (Qs. Maryam: 71), lantas Nabi shallallahu 'alaihi wasallam bersabda: \"Sungguh Allah Azza Wa Jalla telah berfirman: '(Kemudian Kami akan menyelamatkan orang-orang yang bertakwa dan membiarkan orang-orang yang lalim di dalam neraka dalam keadaan berlutut) ' (Qs. Maryam: 72)."},{"p":"Bukhari","n":1173,"ar":"حَدَّثَنَا عَلِيٌّ حَدَّثَنَا سُفْيَانُ قَالَ سَمِعْتُ الزُّهْرِيَّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَمُوتُ لِمُسْلِمٍ ثَلَاثَةٌ مِنْ الْوَلَدِ فَيَلِجَ النَّارَ إِلَّا تَحِلَّةَ الْقَسَمِقَالَ أَبُو عَبْد اللَّهِ{ وَإِنْ مِنْكُمْ إِلَّا وَارِدُهَا }","trj":"Telah menceritakan kepada kami ['Ali] telah menceritakan kepada kami [Sufyan] berkata; aku mendengar [Az Zuhriy] dari [Sa'id bin Al Musayyab] dari [Abu Hurairah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Seorang muslim yang ditinggal wafat oleh tiga orang anaknya, tidak bakalan masuki neraka selain sebatas melakukan sumpah Allah\". Berkata, Abu 'Abdullah: Maksudnya melakukan sumpah Allah yang tersebut dalam Firman-Nya yang artinya; \"Tidaklah dari kalian melainkan pasti akan melewatinya (neraka) (QS. Maryam 71) \". "}],"19:72":[{"p":"Ahmad","n":3885,"ar":"حَدَّثَنَا ابْنُ إِدْرِيسَ قَالَ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرٍ عَنْ أُمِّ مُبَشِّرٍ امْرَأَةِ زَيْدِ بْنِ حَارِثَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَيْتِ حَفْصَةَ فَقَالَ لَا يَدْخُلُ النَّارَ أَحَدٌ شَهِدَ بَدْرًا وَالْحُدَيْبِيَةَ قَالَتْ حَفْصَةُ أَلَيْسَ اللَّهُ عَزَّ وَجَلَّ يَقُولُ{ وَإِنْ مِنْكُمْ إِلَّا وَارِدُهَا }قَالَتْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَهْ{ ثُمَّ نُنَجِّي الَّذِينَ اتَّقَوْا }","trj":"Telah menceritakan kepada kami [Ibnu Idris] berkata, telah menceritakan kepada kami [Al A'masy] dari [Abu Sufyan] dari [Jabir] dari [Ummu Mubasyir] isteri Zaid bin Haritsah, ia berkata, \"Saat Rasulullah shallallahu 'alaihi wasallam berada di rumah Hafshah, beliau bersabda: \"Tidak akan masuk neraka seseorang yang mengikuti perang Badar dan Hudaibiyah.\" Hafshah berkata, \"Bukankah Allah Azza Wa Jalla berfirman: '(Dan tidak ada seorangpun dari padamu, melainkan mendatangi neraka itu) ' (Qs. Maryam: 71). Rasulullah shallallahu 'alaihi wasallam lalu bersabda: \"Lalu bagaimana dengan firman Allah Ta'ala: '(Kemudian kami akan menyelamatkan orang-orang yang bertakwa) ' (Qs. Maryam: 72)."},{"p":"Ahmad","n":4148,"ar":"حَدَّثَنَا حَجَّاجٌ قَالَ أَخْبَرَنِي ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي أَبُو الزُّبَيْرِ أَنَّهُ سَمِعَ جَابِرًا قَالَ حَدَّثَتْنِي أُمُّ مُبَشِّرٍ أَنَّهاسَمِعَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِنْدَ حَفْصَةَ يَقُولُ لَا يَدْخُلُ النَّارَ إِنْ شَاءَ اللَّهُ مِنْ أَصْحَابِ الشَّجَرَةِ أَحَدٌ الَّذِينَ بَايَعُوا تَحْتَهَا فَقَالَتْ بَلَى يَا رَسُولَ اللَّهِ فَانْتَهَرَهَا فَقَالَتْ حَفْصَةُ{ وَإِنْ مِنْكُمْ إِلَّا وَارِدُهَا }فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ قَالَ اللَّهُ عَزَّ وَجَلَّ{ ثُمَّ نُنَجِّي الَّذِينَ اتَّقَوْا وَنَذَرُ الظَّالِمِينَ فِيهَا جِثِيًّا }","trj":"Telah menceritakan kepada kami [Hajjaj] dia berkata, telah mengabarkan kepadaku [Ibnu Juraij] berkata; telah mengabarkan kepadaku [Abu Zubair] bahwa dia mendengar [Jabir] berkata, telah menceritakan kepadaku [Ummu Mubasyir] bahwa dia mendengar Rasulullah shallallahu 'alaihi wasallam waktu berada di samping Hafshah, beliau bersabda: \"Insyaallah tidak akan masuk Neraka orang-orang yang pernah berbaiat di bawah pohon.\" Hafshah berkata, \"Tentu wahai Rasulullah, \" namun beliau menghardiknya hingga Hafshah pun membaca: '(Dan tidak ada seorang pun dari padamu, melainkan mendatangi neraka itu) ' (Qs. Maryam: 71), lantas Nabi shallallahu 'alaihi wasallam bersabda: \"Sungguh Allah Azza Wa Jalla telah berfirman: '(Kemudian Kami akan menyelamatkan orang-orang yang bertakwa dan membiarkan orang-orang yang lalim di dalam neraka dalam keadaan berlutut) ' (Qs. Maryam: 72)."}],"19:77":[{"p":"Ahmad","n":2887,"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا سُفْيَانُ عَنِ الْأَعْمَشِ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ قَالَ قَالَ خَبَّابُ بْنُ الْأَرَتِّكُنْتُ قَيْنًا بِمَكَّةَ فَكُنْتُ أَعْمَلُ لِلْعَاصِ بْنِ وَائِلٍ فَاجْتَمَعَتْ لِي عَلَيْهِ دَرَاهِمُ فَجِئْتُ أَتَقَاضَاهُ فَقَالَ لَا أَقْضِيكَ حَتَّى تَكْفُرَ بِمُحَمَّدٍ قَالَ قُلْتُ وَاللَّهِ لَا أَكْفُرُ بِمُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى تَمُوتَ ثُمَّ تُبْعَثَ قَالَ فَإِذَا بُعِثْتُ كَانَ لِي مَالٌ وَوَلَدٌ قَالَ فَذَكَرْتُ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَنْزَلَ اللَّهُ تَبَارَكَ وَتَعَالَى{ أَفَرَأَيْتَ الَّذِي كَفَرَ بِآيَاتِنَا وَقَالَ لَأُوتَيَنَّ مَالًا وَوَلَدًا حَتَّى بَلَغَ فَرْدًا }","trj":"Telah menceritakan kepada kami [Abdurrazaq] telah mengkabarkan kepada kami [Sufyan] dari [Al A'masy] dari [Abu Dluha] dari [Masruq] dia berkata, bahwa [Khabab bin Al Arts] telah berkata, \"Dulu aku adalah seorang pandai besi di Makkah dan aku bekerja untuk Al Ash bin Wa'il hingga terkumpullah padanya beberapa dirham untukku, kemudian aku datang untuk menagihnya, namun dia berkata, \"Aku tidak akan membayarnya sampai kamu mendustakan Muhammad!\" Khabab berkata, \"Aku lalu berkata, \"Demi Allah, aku tidak akan mendustakan Muhammad shallallahu 'alaihi wasallam sampai kamu mati kemudian kamu dibangkitkan lagi.\" Al Ash bin Wa`il menjawab, \"Jika aku dibangkitkan lagi maka aku akan memiliki harta dan anak.\" Khabab berkata, \"Kemudian hal itu aku sampaikan kepada Nabi shallallahu 'alaihi wasallam, lalu Allah Tabaraka Wa Ta'ala menurunkan ayat: '(Maka apakah kamu Telah melihat orang yang kafir kepada ayat-ayat kami dan ia mengatakan: \"Pasti Aku akan diberi harta dan anak) ' sampai ayat (seorang diri).' (QS. Maryam: 77-80)."},{"p":"Bukhari","n":2114,"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ عَنْ مُسْلِمٍ عَنْ مَسْرُوقٍ حَدَّثَنَا خَبَّابٌ قَالَكُنْتُ رَجُلًا قَيْنًا فَعَمِلْتُ لِلْعَاصِ بْنِ وَائِلٍ فَاجْتَمَعَ لِي عِنْدَهُ فَأَتَيْتُهُ أَتَقَاضَاهُ فَقَالَ لَا وَاللَّهِ لَا أَقْضِيكَ حَتَّى تَكْفُرَ بِمُحَمَّدٍ فَقُلْتُ أَمَا وَاللَّهِ حَتَّى تَمُوتَ ثُمَّ تُبْعَثَ فَلَا قَالَ وَإِنِّي لَمَيِّتٌ ثُمَّ مَبْعُوثٌ قُلْتُ نَعَمْ قَالَ فَإِنَّهُ سَيَكُونُ لِي ثَمَّ مَالٌ وَوَلَدٌ فَأَقْضِيكَ فَأَنْزَلَ اللَّهُ تَعَالَى{ أَفَرَأَيْتَ الَّذِي كَفَرَ بِآيَاتِنَا وَقَالَ لَأُوتَيَنَّ مَالًا وَوَلَدًا }","trj":"Telah menceritakan kepada kami ['Umar bin Hafsh] telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Al A'masy] dari [Muslim] dari [Masruq] telah menceritakan kepada kami [Khabbab] berkata: \"Pada masa Jahiliyyah aku adalah seorang tukang besi dan emas lalu aku bekerja pada Al 'Ash bin Wa'il lalu upahku aku kumpulkan kepadanya kemudian aku menagih agar dia membayarnya. Dia berkata: \"Demi Allah, aku tidak akan membayarnya kepadamu kecuali kamu mau mengingkari (kufur) Muhammad shallallahu 'alaihi wasallam \". Aku katakan: \"Adapun aku, demi Allah tidak akan kufur sampai kamu mati lalu kamu dibangkitkan. Dia berkata: \"Biarkanlah aku sampai aku mati lalu dibangkitkan\". Aku katakan: Baik kalau begitu\". Dia berkata: \"Sungguh aku akan mendapatkan harta dan anak lalu aku akan bayar hutang kepadamu\". Maka Allah Ta'ala menurunkan QS Maryam ayat yang artinya: (\" Maka apakah kamu telah melihat orang yang kafir kepada ayat-ayat kami dan ia mengatakan \"pasti Aku akan diberi harta dan anak\") (QS. Maryam 77)."},{"p":"Bukhari","n":2247,"ar":"حَدَّثَنَا إِسْحَاقُ حَدَّثَنَا وَهْبُ بْنُ جَرِيرِ بْنِ حَازِمٍ أَخْبَرَنَا شُعْبَةُ عَنْ الْأَعْمَشِ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ عَنْ خَبَّابٍ قَالَكُنْتُ قَيْنًا فِي الْجَاهِلِيَّةِ وَكَانَ لِي عَلَى الْعَاصِ بْنِ وَائِلٍ دَرَاهِمُ فَأَتَيْتُهُ أَتَقَاضَاهُ فَقَالَ لَا أَقْضِيكَ حَتَّى تَكْفُرَ بِمُحَمَّدٍ فَقُلْتُ لَا وَاللَّهِ لَا أَكْفُرُ بِمُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى يُمِيتَكَ اللَّهُ ثُمَّ يَبْعَثَكَ قَالَ فَدَعْنِي حَتَّى أَمُوتَ ثُمَّ أُبْعَثَ فَأُوتَى مَالًا وَوَلَدًا ثُمَّ أَقْضِيَكَ فَنَزَلَتْ{ أَفَرَأَيْتَ الَّذِي كَفَرَ بِآيَاتِنَا وَقَالَ لَأُوتَيَنَّ مَالًا وَوَلَدًا }الْآيَةَ","trj":"Telah menceritakan kepada kami [Ishaq] telah menceritakan kepada kami [Wahb bin Jarir bin Hazim] telah mengabarkan kepada kami [Syu'bah] dari [Al A'masy] dari [Abu Adh Dhuha] dari [Masruq] dari [Khabbab] berkata: \"Pada masa Jahiliyyah aku adalah seorang tukang besi dan aku punya uang dirham yang ada pada Al 'Ash bin Wa'il lalu aku menemui dia untuk menagih agar dia membayarnya. Dia berkata: \"Aku tidak akan membayarnya kepadamu kecuali kamu mau mengingkari (kufur) Muhammad shallallahu 'alaihi wasallam \". Aku katakan: \"Demi Allah, aku tidak akan kufur kepada Muhammad shallallahu 'alaihi wasallam sampai Allah mematikan kamu lalu kamu dibangkitkan. Dia berkata: \"Biarkanlah sampai aku mati lalu dibangkitkan dan disana aku akan mendapatkan harta dan anak lalu aku akan bayar hutang kepadamu\". Maka Allah Ta'ala menurunkan QS Maryam ayat yang artinya: (\" Maka apakah kamu telah melihat orang yang kafir kepada ayat-ayat kami dan ia mengatakan \"pasti aku akan diberi harta dan anak\" (QS. Maryam 77)."},{"p":"Bukhari","n":4059,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ عَنْ خَبَّابٍ قَالَكُنْتُ قَيْنًا بِمَكَّةَ فَعَمِلْتُ لِلْعَاصِ بْنِ وَائِلٍ السَّهْمِيِّ سَيْفًا فَجِئْتُ أَتَقَاضَاهُ فَقَالَ لَا أُعْطِيكَ حَتَّى تَكْفُرَ بِمُحَمَّدٍ قُلْتُ لَا أَكْفُرُ بِمُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى يُمِيتَكَ اللَّهُ ثُمَّ يُحْيِيَكَ قَالَ إِذَا أَمَاتَنِي اللَّهُ ثُمَّ بَعَثَنِي وَلِي مَالٌ وَوَلَدٌ فَأَنْزَلَ اللَّهُ{ أَفَرَأَيْتَ الَّذِي كَفَرَ بِآيَاتِنَا وَقَالَ لَأُوتَيَنَّ مَالًا وَوَلَدًا أَطَّلَعَ الْغَيْبَ أَمْ اتَّخَذَ عِنْدَ الرَّحْمَنِ عَهْدًا }قَالَ مَوْثِقًالَمْ يَقُلْ الْأَشْجَعِيُّ عَنْ سُفْيَانَ سَيْفًا وَلَا مَوْثِقًا","trj":"Telah menceritakan kepada kami [Muhammad bin Katsir] Telah mengabarkan kepada kami [Sufyan] dari [Al A'masy] dari [Abu Adl Dluha] dari [Masruq] dari [Khabbab] dia berkata; \"Aku adalah seorang pandai besi di Makkah, dan aku membuatkan sebilah pedang untuk Al Ash bin Wa'il As Sahmi. Tatkala aku mendatanginya untuk menagih bayarannya, dia berkata; \"Aku tidak akan membayarkannya sampai kamu mendustakan Muhammad.\" Khabab berkata; \"Demi Allah, aku tidak akan mendustakan Muhammad shallallahu 'alaihi wasallam sampai kamu dimatikan Allah kemudian kamu dibangkitkan kembali.\" Al Ash bin Wa`il berkata; \"Kalau begitu tunggulah sampai aku mati dan dibangkitkan kembali hingga aku diberi harta dan anak, maka aku akan membayarmu. Maka turunlah ayat ini: 'Maka apakah kamu Telah melihat orang yang kafir kepada ayat-ayat kami dan ia mengatakan: \"Pasti Aku akan diberi harta dan anak. Adakah ia melihat yang ghaib atau ia telah membuat perjanjian di sisi Tuhan Yang Maha Pemurah?. (QS. Maryam: 77-78). Khabab berkata; Yaitu ikatan janji. Namun [Al Asyja'i] tidak menyebutkan lafazh 'saif' (pedang) dan 'Mautsiq' (perjanjian)."},{"p":"Bukhari","n":4060,"ar":"حَدَّثَنَا بِشْرُ بْنُ خَالِدٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ سُلَيْمَانَ سَمِعْتُ أَبَا الضُّحَى يُحَدِّثُ عَنْ مَسْرُوقٍ عَنْ خَبَّابٍ قَالَكُنْتُ قَيْنًا فِي الْجَاهِلِيَّةِ وَكَانَ لِي دَيْنٌ عَلَى الْعَاصِ بْنِ وَائِلٍ قَالَ فَأَتَاهُ يَتَقَاضَاهُ فَقَالَ لَا أُعْطِيكَ حَتَّى تَكْفُرَ بِمُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ وَاللَّهِ لَا أَكْفُرُ حَتَّى يُمِيتَكَ اللَّهُ ثُمَّ يَبْعَثَكَ قَالَ فَذَرْنِي حَتَّى أَمُوتَ ثُمَّ أُبْعَثَ فَسَوْفَ أُوتَى مَالًا وَوَلَدًا فَأَقْضِيكَ فَنَزَلَتْ هَذِهِ الْآيَةُ{ أَفَرَأَيْتَ الَّذِي كَفَرَ بِآيَاتِنَا وَقَالَ لَأُوتَيَنَّ مَالًا وَوَلَدًا }","trj":"Telah menceritakan kepada kami [Bisyr bin Khalid] Telah menceritakan kepada kami [Muhammad bin Ja'far] Telah menceritakan kepada kami [Syu'bah] dari [Sulaiman] Aku mendengar [Abu Adl Dluha] bercerita dari [Masruq] dari [Khabbab] dia berkata; \"Pada masa Jahiliyah aku adalah seorang pandai besi, dan Al Ash bin Wa'il mempunyai hutang kepadaku. Khabab berkata; maka aku datang kepadanya untuk menagihnya, namun dia berkata; \"Aku tidak akan membayarkannya sampai kamu mendustakan Muhammad.\" Khabab berkata; \"Demi Allah, aku tidak akan mendustakan Muhammad shallallahu 'alaihi wasallam sampai kamu dimatikan Allah kemudian kamu dibangkitkan kembali.\" Al Ash bin Wa`il berkata; \"Kalau begitu tunggulah sampai aku mati dan dibangkitkan kembali hingga aku diberi harta dan anak, maka aku akan membayarmu. Maka turunlah ayat ini: 'Maka apakah kamu Telah melihat orang yang kafir kepada ayat-ayat kami dan ia mengatakan: \"Pasti Aku akan diberi harta dan anak. (QS. Maryam: 77)."},{"p":"Bukhari","n":4061,"ar":"حَدَّثَنَا يَحْيَى حَدَّثَنَا وَكِيعٌ عَنْ الْأَعْمَشِ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ عَنْ خَبَّابٍ قَالَكُنْتُ رَجُلًا قَيْنًا وَكَانَ لِي عَلَى الْعَاصِ بْنِ وَائِلٍ دَيْنٌ فَأَتَيْتُهُ أَتَقَاضَاهُ فَقَالَ لِي لَا أَقْضِيكَ حَتَّى تَكْفُرَ بِمُحَمَّدٍ قَالَ قُلْتُ لَنْ أَكْفُرَ بِهِ حَتَّى تَمُوتَ ثُمَّ تُبْعَثَ قَالَ وَإِنِّي لَمَبْعُوثٌ مِنْ بَعْدِ الْمَوْتِ فَسَوْفَ أَقْضِيكَ إِذَا رَجَعْتُ إِلَى مَالٍ وَوَلَدٍ قَالَ فَنَزَلَتْ{ أَفَرَأَيْتَ الَّذِي كَفَرَ بِآيَاتِنَا وَقَالَ لَأُوتَيَنَّ مَالًا وَوَلَدًا أَطَّلَعَ الْغَيْبَ أَمْ اتَّخَذَ عِنْدَ الرَّحْمَنِ عَهْدًا كَلَّا سَنَكْتُبُ مَا يَقُولُ وَنَمُدُّ لَهُ مِنْ الْعَذَابِ مَدًّا وَنَرِثُهُ مَا يَقُولُ وَيَأْتِينَا فَرْدًا }","trj":"Telah menceritakan kepada kami [Yahya] Telah menceritakan kepada kami [Waki'] dari [Al A'masy] dari [Abu Adl Dluha] dari [Masruq] dari [Khabbab] dia berkata; \"Aku adalah seorang pandai besi yang bekerja untuk Al Ash bin Wa'il, ketika aku datang untuk menagih gajiku, dia berkata; \"Tidak, demi Allah aku tidak akan membayarkannya sampai kamu mendustakan Muhammad.\" Khabab berkata; \"Demi Allah, aku tidak akan mendustakan Muhammad shallallahu 'alaihi wasallam sampai kamu mati kemudian kamu dibangkitkan kembali.\" Al Ash bin Wa`il berkata; \"Apabila aku mati dan dibangkitkan serta dapat kembali kepada harta dan anakku, maka baru aku akan membayarmu!\" Khabbab berkata; maka turunlah ayat: 'Maka apakah kamu Telah melihat orang yang kafir kepada ayat-ayat kami dan ia mengatakan: \"Pasti Aku akan diberi harta dan anak. Adakah ia melihat yang ghaib atau ia telah membuat perjanjian di sisi Tuhan Yang Maha Pemurah? sekali-kali tidak, Kami akan menulis apa yang ia katakan, dan benar-benar Kami akan memperpanjang azab untuknya, dan Kami akan mewarisi apa yang ia katakan itu, dan ia akan datang kepada Kami dengan seorang diri. (QS. Maryam: 77-80)."}],"19:78":[{"p":"Ahmad","n":2887,"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا سُفْيَانُ عَنِ الْأَعْمَشِ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ قَالَ قَالَ خَبَّابُ بْنُ الْأَرَتِّكُنْتُ قَيْنًا بِمَكَّةَ فَكُنْتُ أَعْمَلُ لِلْعَاصِ بْنِ وَائِلٍ فَاجْتَمَعَتْ لِي عَلَيْهِ دَرَاهِمُ فَجِئْتُ أَتَقَاضَاهُ فَقَالَ لَا أَقْضِيكَ حَتَّى تَكْفُرَ بِمُحَمَّدٍ قَالَ قُلْتُ وَاللَّهِ لَا أَكْفُرُ بِمُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى تَمُوتَ ثُمَّ تُبْعَثَ قَالَ فَإِذَا بُعِثْتُ كَانَ لِي مَالٌ وَوَلَدٌ قَالَ فَذَكَرْتُ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَنْزَلَ اللَّهُ تَبَارَكَ وَتَعَالَى{ أَفَرَأَيْتَ الَّذِي كَفَرَ بِآيَاتِنَا وَقَالَ لَأُوتَيَنَّ مَالًا وَوَلَدًا حَتَّى بَلَغَ فَرْدًا }","trj":"Telah menceritakan kepada kami [Abdurrazaq] telah mengkabarkan kepada kami [Sufyan] dari [Al A'masy] dari [Abu Dluha] dari [Masruq] dia berkata, bahwa [Khabab bin Al Arts] telah berkata, \"Dulu aku adalah seorang pandai besi di Makkah dan aku bekerja untuk Al Ash bin Wa'il hingga terkumpullah padanya beberapa dirham untukku, kemudian aku datang untuk menagihnya, namun dia berkata, \"Aku tidak akan membayarnya sampai kamu mendustakan Muhammad!\" Khabab berkata, \"Aku lalu berkata, \"Demi Allah, aku tidak akan mendustakan Muhammad shallallahu 'alaihi wasallam sampai kamu mati kemudian kamu dibangkitkan lagi.\" Al Ash bin Wa`il menjawab, \"Jika aku dibangkitkan lagi maka aku akan memiliki harta dan anak.\" Khabab berkata, \"Kemudian hal itu aku sampaikan kepada Nabi shallallahu 'alaihi wasallam, lalu Allah Tabaraka Wa Ta'ala menurunkan ayat: '(Maka apakah kamu Telah melihat orang yang kafir kepada ayat-ayat kami dan ia mengatakan: \"Pasti Aku akan diberi harta dan anak) ' sampai ayat (seorang diri).' (QS. Maryam: 77-80)."},{"p":"Bukhari","n":4059,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ عَنْ خَبَّابٍ قَالَكُنْتُ قَيْنًا بِمَكَّةَ فَعَمِلْتُ لِلْعَاصِ بْنِ وَائِلٍ السَّهْمِيِّ سَيْفًا فَجِئْتُ أَتَقَاضَاهُ فَقَالَ لَا أُعْطِيكَ حَتَّى تَكْفُرَ بِمُحَمَّدٍ قُلْتُ لَا أَكْفُرُ بِمُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى يُمِيتَكَ اللَّهُ ثُمَّ يُحْيِيَكَ قَالَ إِذَا أَمَاتَنِي اللَّهُ ثُمَّ بَعَثَنِي وَلِي مَالٌ وَوَلَدٌ فَأَنْزَلَ اللَّهُ{ أَفَرَأَيْتَ الَّذِي كَفَرَ بِآيَاتِنَا وَقَالَ لَأُوتَيَنَّ مَالًا وَوَلَدًا أَطَّلَعَ الْغَيْبَ أَمْ اتَّخَذَ عِنْدَ الرَّحْمَنِ عَهْدًا }قَالَ مَوْثِقًالَمْ يَقُلْ الْأَشْجَعِيُّ عَنْ سُفْيَانَ سَيْفًا وَلَا مَوْثِقًا","trj":"Telah menceritakan kepada kami [Muhammad bin Katsir] Telah mengabarkan kepada kami [Sufyan] dari [Al A'masy] dari [Abu Adl Dluha] dari [Masruq] dari [Khabbab] dia berkata; \"Aku adalah seorang pandai besi di Makkah, dan aku membuatkan sebilah pedang untuk Al Ash bin Wa'il As Sahmi. Tatkala aku mendatanginya untuk menagih bayarannya, dia berkata; \"Aku tidak akan membayarkannya sampai kamu mendustakan Muhammad.\" Khabab berkata; \"Demi Allah, aku tidak akan mendustakan Muhammad shallallahu 'alaihi wasallam sampai kamu dimatikan Allah kemudian kamu dibangkitkan kembali.\" Al Ash bin Wa`il berkata; \"Kalau begitu tunggulah sampai aku mati dan dibangkitkan kembali hingga aku diberi harta dan anak, maka aku akan membayarmu. Maka turunlah ayat ini: 'Maka apakah kamu Telah melihat orang yang kafir kepada ayat-ayat kami dan ia mengatakan: \"Pasti Aku akan diberi harta dan anak. Adakah ia melihat yang ghaib atau ia telah membuat perjanjian di sisi Tuhan Yang Maha Pemurah?. (QS. Maryam: 77-78). Khabab berkata; Yaitu ikatan janji. Namun [Al Asyja'i] tidak menyebutkan lafazh 'saif' (pedang) dan 'Mautsiq' (perjanjian)."},{"p":"Bukhari","n":4061,"ar":"حَدَّثَنَا يَحْيَى حَدَّثَنَا وَكِيعٌ عَنْ الْأَعْمَشِ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ عَنْ خَبَّابٍ قَالَكُنْتُ رَجُلًا قَيْنًا وَكَانَ لِي عَلَى الْعَاصِ بْنِ وَائِلٍ دَيْنٌ فَأَتَيْتُهُ أَتَقَاضَاهُ فَقَالَ لِي لَا أَقْضِيكَ حَتَّى تَكْفُرَ بِمُحَمَّدٍ قَالَ قُلْتُ لَنْ أَكْفُرَ بِهِ حَتَّى تَمُوتَ ثُمَّ تُبْعَثَ قَالَ وَإِنِّي لَمَبْعُوثٌ مِنْ بَعْدِ الْمَوْتِ فَسَوْفَ أَقْضِيكَ إِذَا رَجَعْتُ إِلَى مَالٍ وَوَلَدٍ قَالَ فَنَزَلَتْ{ أَفَرَأَيْتَ الَّذِي كَفَرَ بِآيَاتِنَا وَقَالَ لَأُوتَيَنَّ مَالًا وَوَلَدًا أَطَّلَعَ الْغَيْبَ أَمْ اتَّخَذَ عِنْدَ الرَّحْمَنِ عَهْدًا كَلَّا سَنَكْتُبُ مَا يَقُولُ وَنَمُدُّ لَهُ مِنْ الْعَذَابِ مَدًّا وَنَرِثُهُ مَا يَقُولُ وَيَأْتِينَا فَرْدًا }","trj":"Telah menceritakan kepada kami [Yahya] Telah menceritakan kepada kami [Waki'] dari [Al A'masy] dari [Abu Adl Dluha] dari [Masruq] dari [Khabbab] dia berkata; \"Aku adalah seorang pandai besi yang bekerja untuk Al Ash bin Wa'il, ketika aku datang untuk menagih gajiku, dia berkata; \"Tidak, demi Allah aku tidak akan membayarkannya sampai kamu mendustakan Muhammad.\" Khabab berkata; \"Demi Allah, aku tidak akan mendustakan Muhammad shallallahu 'alaihi wasallam sampai kamu mati kemudian kamu dibangkitkan kembali.\" Al Ash bin Wa`il berkata; \"Apabila aku mati dan dibangkitkan serta dapat kembali kepada harta dan anakku, maka baru aku akan membayarmu!\" Khabbab berkata; maka turunlah ayat: 'Maka apakah kamu Telah melihat orang yang kafir kepada ayat-ayat kami dan ia mengatakan: \"Pasti Aku akan diberi harta dan anak. Adakah ia melihat yang ghaib atau ia telah membuat perjanjian di sisi Tuhan Yang Maha Pemurah? sekali-kali tidak, Kami akan menulis apa yang ia katakan, dan benar-benar Kami akan memperpanjang azab untuknya, dan Kami akan mewarisi apa yang ia katakan itu, dan ia akan datang kepada Kami dengan seorang diri. (QS. Maryam: 77-80)."}],"19:79":[{"p":"Ahmad","n":2887,"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا سُفْيَانُ عَنِ الْأَعْمَشِ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ قَالَ قَالَ خَبَّابُ بْنُ الْأَرَتِّكُنْتُ قَيْنًا بِمَكَّةَ فَكُنْتُ أَعْمَلُ لِلْعَاصِ بْنِ وَائِلٍ فَاجْتَمَعَتْ لِي عَلَيْهِ دَرَاهِمُ فَجِئْتُ أَتَقَاضَاهُ فَقَالَ لَا أَقْضِيكَ حَتَّى تَكْفُرَ بِمُحَمَّدٍ قَالَ قُلْتُ وَاللَّهِ لَا أَكْفُرُ بِمُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى تَمُوتَ ثُمَّ تُبْعَثَ قَالَ فَإِذَا بُعِثْتُ كَانَ لِي مَالٌ وَوَلَدٌ قَالَ فَذَكَرْتُ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَنْزَلَ اللَّهُ تَبَارَكَ وَتَعَالَى{ أَفَرَأَيْتَ الَّذِي كَفَرَ بِآيَاتِنَا وَقَالَ لَأُوتَيَنَّ مَالًا وَوَلَدًا حَتَّى بَلَغَ فَرْدًا }","trj":"Telah menceritakan kepada kami [Abdurrazaq] telah mengkabarkan kepada kami [Sufyan] dari [Al A'masy] dari [Abu Dluha] dari [Masruq] dia berkata, bahwa [Khabab bin Al Arts] telah berkata, \"Dulu aku adalah seorang pandai besi di Makkah dan aku bekerja untuk Al Ash bin Wa'il hingga terkumpullah padanya beberapa dirham untukku, kemudian aku datang untuk menagihnya, namun dia berkata, \"Aku tidak akan membayarnya sampai kamu mendustakan Muhammad!\" Khabab berkata, \"Aku lalu berkata, \"Demi Allah, aku tidak akan mendustakan Muhammad shallallahu 'alaihi wasallam sampai kamu mati kemudian kamu dibangkitkan lagi.\" Al Ash bin Wa`il menjawab, \"Jika aku dibangkitkan lagi maka aku akan memiliki harta dan anak.\" Khabab berkata, \"Kemudian hal itu aku sampaikan kepada Nabi shallallahu 'alaihi wasallam, lalu Allah Tabaraka Wa Ta'ala menurunkan ayat: '(Maka apakah kamu Telah melihat orang yang kafir kepada ayat-ayat kami dan ia mengatakan: \"Pasti Aku akan diberi harta dan anak) ' sampai ayat (seorang diri).' (QS. Maryam: 77-80)."},{"p":"Bukhari","n":4061,"ar":"حَدَّثَنَا يَحْيَى حَدَّثَنَا وَكِيعٌ عَنْ الْأَعْمَشِ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ عَنْ خَبَّابٍ قَالَكُنْتُ رَجُلًا قَيْنًا وَكَانَ لِي عَلَى الْعَاصِ بْنِ وَائِلٍ دَيْنٌ فَأَتَيْتُهُ أَتَقَاضَاهُ فَقَالَ لِي لَا أَقْضِيكَ حَتَّى تَكْفُرَ بِمُحَمَّدٍ قَالَ قُلْتُ لَنْ أَكْفُرَ بِهِ حَتَّى تَمُوتَ ثُمَّ تُبْعَثَ قَالَ وَإِنِّي لَمَبْعُوثٌ مِنْ بَعْدِ الْمَوْتِ فَسَوْفَ أَقْضِيكَ إِذَا رَجَعْتُ إِلَى مَالٍ وَوَلَدٍ قَالَ فَنَزَلَتْ{ أَفَرَأَيْتَ الَّذِي كَفَرَ بِآيَاتِنَا وَقَالَ لَأُوتَيَنَّ مَالًا وَوَلَدًا أَطَّلَعَ الْغَيْبَ أَمْ اتَّخَذَ عِنْدَ الرَّحْمَنِ عَهْدًا كَلَّا سَنَكْتُبُ مَا يَقُولُ وَنَمُدُّ لَهُ مِنْ الْعَذَابِ مَدًّا وَنَرِثُهُ مَا يَقُولُ وَيَأْتِينَا فَرْدًا }","trj":"Telah menceritakan kepada kami [Yahya] Telah menceritakan kepada kami [Waki'] dari [Al A'masy] dari [Abu Adl Dluha] dari [Masruq] dari [Khabbab] dia berkata; \"Aku adalah seorang pandai besi yang bekerja untuk Al Ash bin Wa'il, ketika aku datang untuk menagih gajiku, dia berkata; \"Tidak, demi Allah aku tidak akan membayarkannya sampai kamu mendustakan Muhammad.\" Khabab berkata; \"Demi Allah, aku tidak akan mendustakan Muhammad shallallahu 'alaihi wasallam sampai kamu mati kemudian kamu dibangkitkan kembali.\" Al Ash bin Wa`il berkata; \"Apabila aku mati dan dibangkitkan serta dapat kembali kepada harta dan anakku, maka baru aku akan membayarmu!\" Khabbab berkata; maka turunlah ayat: 'Maka apakah kamu Telah melihat orang yang kafir kepada ayat-ayat kami dan ia mengatakan: \"Pasti Aku akan diberi harta dan anak. Adakah ia melihat yang ghaib atau ia telah membuat perjanjian di sisi Tuhan Yang Maha Pemurah? sekali-kali tidak, Kami akan menulis apa yang ia katakan, dan benar-benar Kami akan memperpanjang azab untuknya, dan Kami akan mewarisi apa yang ia katakan itu, dan ia akan datang kepada Kami dengan seorang diri. (QS. Maryam: 77-80)."}],"19:80":[{"p":"Ahmad","n":2887,"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا سُفْيَانُ عَنِ الْأَعْمَشِ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ قَالَ قَالَ خَبَّابُ بْنُ الْأَرَتِّكُنْتُ قَيْنًا بِمَكَّةَ فَكُنْتُ أَعْمَلُ لِلْعَاصِ بْنِ وَائِلٍ فَاجْتَمَعَتْ لِي عَلَيْهِ دَرَاهِمُ فَجِئْتُ أَتَقَاضَاهُ فَقَالَ لَا أَقْضِيكَ حَتَّى تَكْفُرَ بِمُحَمَّدٍ قَالَ قُلْتُ وَاللَّهِ لَا أَكْفُرُ بِمُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى تَمُوتَ ثُمَّ تُبْعَثَ قَالَ فَإِذَا بُعِثْتُ كَانَ لِي مَالٌ وَوَلَدٌ قَالَ فَذَكَرْتُ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَنْزَلَ اللَّهُ تَبَارَكَ وَتَعَالَى{ أَفَرَأَيْتَ الَّذِي كَفَرَ بِآيَاتِنَا وَقَالَ لَأُوتَيَنَّ مَالًا وَوَلَدًا حَتَّى بَلَغَ فَرْدًا }","trj":"Telah menceritakan kepada kami [Abdurrazaq] telah mengkabarkan kepada kami [Sufyan] dari [Al A'masy] dari [Abu Dluha] dari [Masruq] dia berkata, bahwa [Khabab bin Al Arts] telah berkata, \"Dulu aku adalah seorang pandai besi di Makkah dan aku bekerja untuk Al Ash bin Wa'il hingga terkumpullah padanya beberapa dirham untukku, kemudian aku datang untuk menagihnya, namun dia berkata, \"Aku tidak akan membayarnya sampai kamu mendustakan Muhammad!\" Khabab berkata, \"Aku lalu berkata, \"Demi Allah, aku tidak akan mendustakan Muhammad shallallahu 'alaihi wasallam sampai kamu mati kemudian kamu dibangkitkan lagi.\" Al Ash bin Wa`il menjawab, \"Jika aku dibangkitkan lagi maka aku akan memiliki harta dan anak.\" Khabab berkata, \"Kemudian hal itu aku sampaikan kepada Nabi shallallahu 'alaihi wasallam, lalu Allah Tabaraka Wa Ta'ala menurunkan ayat: '(Maka apakah kamu Telah melihat orang yang kafir kepada ayat-ayat kami dan ia mengatakan: \"Pasti Aku akan diberi harta dan anak) ' sampai ayat (seorang diri).' (QS. Maryam: 77-80)."},{"p":"Bukhari","n":4061,"ar":"حَدَّثَنَا يَحْيَى حَدَّثَنَا وَكِيعٌ عَنْ الْأَعْمَشِ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ عَنْ خَبَّابٍ قَالَكُنْتُ رَجُلًا قَيْنًا وَكَانَ لِي عَلَى الْعَاصِ بْنِ وَائِلٍ دَيْنٌ فَأَتَيْتُهُ أَتَقَاضَاهُ فَقَالَ لِي لَا أَقْضِيكَ حَتَّى تَكْفُرَ بِمُحَمَّدٍ قَالَ قُلْتُ لَنْ أَكْفُرَ بِهِ حَتَّى تَمُوتَ ثُمَّ تُبْعَثَ قَالَ وَإِنِّي لَمَبْعُوثٌ مِنْ بَعْدِ الْمَوْتِ فَسَوْفَ أَقْضِيكَ إِذَا رَجَعْتُ إِلَى مَالٍ وَوَلَدٍ قَالَ فَنَزَلَتْ{ أَفَرَأَيْتَ الَّذِي كَفَرَ بِآيَاتِنَا وَقَالَ لَأُوتَيَنَّ مَالًا وَوَلَدًا أَطَّلَعَ الْغَيْبَ أَمْ اتَّخَذَ عِنْدَ الرَّحْمَنِ عَهْدًا كَلَّا سَنَكْتُبُ مَا يَقُولُ وَنَمُدُّ لَهُ مِنْ الْعَذَابِ مَدًّا وَنَرِثُهُ مَا يَقُولُ وَيَأْتِينَا فَرْدًا }","trj":"Telah menceritakan kepada kami [Yahya] Telah menceritakan kepada kami [Waki'] dari [Al A'masy] dari [Abu Adl Dluha] dari [Masruq] dari [Khabbab] dia berkata; \"Aku adalah seorang pandai besi yang bekerja untuk Al Ash bin Wa'il, ketika aku datang untuk menagih gajiku, dia berkata; \"Tidak, demi Allah aku tidak akan membayarkannya sampai kamu mendustakan Muhammad.\" Khabab berkata; \"Demi Allah, aku tidak akan mendustakan Muhammad shallallahu 'alaihi wasallam sampai kamu mati kemudian kamu dibangkitkan kembali.\" Al Ash bin Wa`il berkata; \"Apabila aku mati dan dibangkitkan serta dapat kembali kepada harta dan anakku, maka baru aku akan membayarmu!\" Khabbab berkata; maka turunlah ayat: 'Maka apakah kamu Telah melihat orang yang kafir kepada ayat-ayat kami dan ia mengatakan: \"Pasti Aku akan diberi harta dan anak. Adakah ia melihat yang ghaib atau ia telah membuat perjanjian di sisi Tuhan Yang Maha Pemurah? sekali-kali tidak, Kami akan menulis apa yang ia katakan, dan benar-benar Kami akan memperpanjang azab untuknya, dan Kami akan mewarisi apa yang ia katakan itu, dan ia akan datang kepada Kami dengan seorang diri. (QS. Maryam: 77-80)."}]},"mapping_surah":[{"p":"Ahmad","n":2887,"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا سُفْيَانُ عَنِ الْأَعْمَشِ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ قَالَ قَالَ خَبَّابُ بْنُ الْأَرَتِّكُنْتُ قَيْنًا بِمَكَّةَ فَكُنْتُ أَعْمَلُ لِلْعَاصِ بْنِ وَائِلٍ فَاجْتَمَعَتْ لِي عَلَيْهِ دَرَاهِمُ فَجِئْتُ أَتَقَاضَاهُ فَقَالَ لَا أَقْضِيكَ حَتَّى تَكْفُرَ بِمُحَمَّدٍ قَالَ قُلْتُ وَاللَّهِ لَا أَكْفُرُ بِمُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى تَمُوتَ ثُمَّ تُبْعَثَ قَالَ فَإِذَا بُعِثْتُ كَانَ لِي مَالٌ وَوَلَدٌ قَالَ فَذَكَرْتُ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَنْزَلَ اللَّهُ تَبَارَكَ وَتَعَالَى{ أَفَرَأَيْتَ الَّذِي كَفَرَ بِآيَاتِنَا وَقَالَ لَأُوتَيَنَّ مَالًا وَوَلَدًا حَتَّى بَلَغَ فَرْدًا }","trj":"Telah menceritakan kepada kami [Abdurrazaq] telah mengkabarkan kepada kami [Sufyan] dari [Al A'masy] dari [Abu Dluha] dari [Masruq] dia berkata, bahwa [Khabab bin Al Arts] telah berkata, \"Dulu aku adalah seorang pandai besi di Makkah dan aku bekerja untuk Al Ash bin Wa'il hingga terkumpullah padanya beberapa dirham untukku, kemudian aku datang untuk menagihnya, namun dia berkata, \"Aku tidak akan membayarnya sampai kamu mendustakan Muhammad!\" Khabab berkata, \"Aku lalu berkata, \"Demi Allah, aku tidak akan mendustakan Muhammad shallallahu 'alaihi wasallam sampai kamu mati kemudian kamu dibangkitkan lagi.\" Al Ash bin Wa`il menjawab, \"Jika aku dibangkitkan lagi maka aku akan memiliki harta dan anak.\" Khabab berkata, \"Kemudian hal itu aku sampaikan kepada Nabi shallallahu 'alaihi wasallam, lalu Allah Tabaraka Wa Ta'ala menurunkan ayat: '(Maka apakah kamu Telah melihat orang yang kafir kepada ayat-ayat kami dan ia mengatakan: \"Pasti Aku akan diberi harta dan anak) ' sampai ayat (seorang diri).' (QS. Maryam: 77-80)."},{"p":"Ahmad","n":3270,"ar":"حَدَّثَنَا يَعْقُوبُ حَدَّثَنَا أَبِي عَنْ مُحَمَّدِ بْنِ إِسْحَاقَ حَدَّثَنِي مُحَمَّدُ بْنُ مُسْلِمِ بْنِ عَبْدِ اللَّهِ بْنِ شِهَابٍ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ بْنِ هِشَامٍ الْمَخْزُومِيِّ عَنْ أُمِّ سَلَمَةَ ابْنَةِ أَبِي أُمَيَّةَ بْنِ الْمُغِيرَةِ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْلَمَّا نَزَلْنَا أَرْضَ الْحَبَشَةِ جَاوَرْنَا بِهَا خَيْرَ جَارٍ النَّجَاشِيَّ أَمَّنَّا عَلَى دِينِنَا وَعَبَدْنَا اللَّهَ تَعَالَى لَا نُؤْذَى وَلَا نَسْمَعُ شَيْئًا نَكْرَهُهُ فَلَمَّا بَلَغَ ذَلِكَ قُرَيْشًا ائْتَمَرُوا أَنْ يَبْعَثُوا إِلَى النَّجَاشِيِّ فِينَا رَجُلَيْنِ جَلْدَيْنِ وَأَنْ يُهْدُوا لِلنَّجَاشِيِّ هَدَايَا مِمَّا يُسْتَطْرَفُ مِنْ مَتَاعِ مَكَّةَ وَكَانَ مِنْ أَعْجَبِ مَا يَأْتِيهِ مِنْهَا إِلَيْهِ الْأَدَمُ فَجَمَعُوا لَهُ أَدَمًا كَثِيرًا وَلَمْ يَتْرُكُوا مِنْ بَطَارِقَتِهِ بِطْرِيقًا إِلَّا أَهْدَوْا لَهُ هَدِيَّةً ثُمَّ بَعَثُوا بِذَلِكَ عَبْدَ اللَّهِ بْنَ أَبِي رَبِيعَةَ بْنِ الْمُغِيرَةِ الْمَخْزُومِيَّ وَعَمْرَو بْنَ الْعَاصِ بْنِ وَائِلٍ السَّهْمِيَّ وَأَمَرُوهُمَا أَمْرَهُمْ وَقَالُوا لَهُمَا ادْفَعَا إِلَى كُلِّ بِطْرِيقٍ هَدِيَّتَهُ قَبْلَ أَنْ تُكَلِّمُوا النَّجَاشِيَّ فِيهِمْ ثُمَّ قَدِّمُوا لِلنَّجَاشِيِّ هَدَايَاهُ ثُمَّ سَلُوهُ أَنْ يُسَلِّمَهُمْ إِلَيْكُمْ قَبْلَ أَنْ يُكَلِّمَهُمْ قَالَتْ فَخَرَجَا فَقَدِمَا عَلَى النَّجَاشِيِّ وَنَحْنُ عِنْدَهُ بِخَيْرِ دَارٍ وَخَيْرِ جَارٍ فَلَمْ يَبْقَ مِنْ بَطَارِقَتِهِ بِطْرِيقٌ إِلَّا دَفَعَا إِلَيْهِ هَدِيَّتَهُ قَبْلَ أَنْ يُكَلِّمَا النَّجَاشِيَّ ثُمَّ قَالَ لِكُلِّ بِطْرِيقٍ مِنْهُمْ إِنَّهُ قَدْ صَبَا إِلَى بَلَدِ الْمَلِكِ مِنَّا غِلْمَانٌ سُفَهَاءُ فَارَقُوا دِينَ قَوْمِهِمْ وَلَمْ يَدْخُلُوا فِي دِينِكُمْ وَجَاءُوا بِدِينٍ مُبْتَدَعٍ لَا نَعْرِفُهُ نَحْنُ وَلَا أَنْتُمْ وَقَدْ بَعَثَنَا إِلَى الْمَلِكِ فِيهِمْ أَشْرَافُ قَوْمِهِمْ لِنَرُدَّهُمْ إِلَيْهِمْ فَإِذَا كَلَّمْنَا الْمَلِكَ فِيهِمْ فَأَشِيرُوا عَلَيْهِ بِأَنْ يُسَلِّمَهُمْ إِلَيْنَا وَلَا يُكَلِّمَهُمْ ف��إِنَّ قَوْمَهُمْ أَعْلَى بِهِمْ عَيْنًا وَأَعْلَمُ بِمَا عَابُوا عَلَيْهِمْ فَقَالُوا لَهُمَا نَعَمْ ثُمَّ إِنَّهُمَا قَرَّبَا هَدَايَاهُمْ إِلَى النَّجَاشِيِّ فَقَبِلَهَا مِنْهُمَا ثُمَّ كَلَّمَاهُ فَقَالَا لَهُ أَيُّهَا الْمَلِكُ إِنَّهُ قَدْ صَبَا إِلَى بَلَدِكَ مِنَّا غِلْمَانٌ سُفَهَاءُ فَارَقُوا دِينَ قَوْمِهِمْ وَلَمْ يَدْخُلُوا فِي دِينِكَ وَجَاءُوا بِدِينٍ مُبْتَدَعٍ لَا نَعْرِفُهُ نَحْنُ وَلَا أَنْتَ وَقَدْ بَعَثَنَا إِلَيْكَ فِيهِمْ أَشْرَافُ قَوْمِهِمْ مِنْ آبَائِهِمْ وَأَعْمَامِهِمْ وَعَشَائِرِهِمْ لِتَرُدَّهُمْ إِلَيْهِمْ فَهُمْ أَعْلَى بِهِمْ عَيْنًا وَأَعْلَمُ بِمَا عَابُوا عَلَيْهِمْ وَعَاتَبُوهُمْ فِيهِ قَالَتْ وَلَمْ يَكُنْ شَيْءٌ أَبْغَضُ إِلَى عَبْدِ اللَّهِ بْنِ أَبِي رَبِيعَةَ وَعَمْرِو بْنِ الْعَاصِ مِنْ أَنْ يَسْمَعَ النَّجَاشِيُّ كَلَامَهُمْ فَقَالَتْ بَطَارِقَتُهُ حَوْلَهُ صَدَقُوا أَيُّهَا الْمَلِكُ قَوْمُهُمْ أَعْلَى بِهِمْ عَيْنًا وَأَعْلَمُ بِمَا عَابُوا عَلَيْهِمْ فَأَسْلِمْهُمْ إِلَيْهِمَا فَلْيَرُدَّانِهِمْ إِلَى بِلَادِهِمْ وَقَوْمِهِمْ قَالَ فَغَضِبَ النَّجَاشِيُّ ثُمَّ قَالَ لَا هَايْمُ اللَّهِ إِذًا لَا أُسْلِمَهُمْ إِلَيْهِمَا وَلَا أَكَادُ قَوْمًا جَاوَرُونِي وَنَزَلُوا بِلَادِي وَاخْتَارُونِي عَلَى مَنْ سِوَايَ حَتَّى أَدْعُوَهُمْ فَأَسْأَلَهُمْ مَا يَقُولُ هَذَانِ فِي أَمْرِهِمْ فَإِنْ كَانُوا كَمَا يَقُولَانِ أَسْلَمْتُهُمْ إِلَيْهِمَا وَرَدَدْتُهُمْ إِلَى قَوْمِهِمْ وَإِنْ كَانُوا عَلَى غَيْرِ ذَلِكَ مَنَعْتُهُمْ مِنْهُمَا وَأَحْسَنْتُ جِوَارَهُمْ مَا جَاوَرُونِي قَالَتْ ثُمَّ أَرْسَلَ إِلَى أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَدَعَاهُمْ فَلَمَّا جَاءَهُمْ رَسُولُهُ اجْتَمَعُوا ثُمَّ قَالَ بَعْضُهُمْ لِبَعْضٍ مَا تَقُولُونَ لِلرَّجُلِ إِذَا جِئْتُمُوهُ قَالُوا نَقُولُ وَاللَّهِ مَا عَلِمْنَا وَمَا أَمَرَنَا بِهِ نَبِيُّنَا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَائِنٌ فِي ذَلِكَ مَا هُوَ كَائِنٌ فَلَمَّا جَاءُوهُ وَقَدْ دَعَا النَّجَاشِيُّ أَسَاقِفَتَهُ فَنَشَرُوا مَصَاحِفَهُمْ حَوْلَهُ لِيَسْأَلَهُمْ فَقَالَ مَا هَذَا الدِّينُ الَّذِي فَارَقْتُمْ فِيهِ قَوْمَكُمْ وَلَمْ تَدْخُلُوا فِي دِينِي وَلَا فِي دِينِ أَحَدٍ مِنْ هَذِهِ الْأُمَمِ قَالَتْ فَكَانَ الَّذِي كَلَّمَهُ جَعْفَرُ بْنُ أَبِي طَالِبٍ فَقَالَ لَهُ أَيُّهَا الْمَلِكُ كُنَّا قَوْمًا أَهْلَ جَاهِلِيَّةٍ نَعْبُدُ الْأَصْنَامَ وَنَأْكُلُ الْمَيْتَةَ وَنَأْتِي الْفَوَاحِشَ وَنَقْطَعُ الْأَرْحَامَ وَنُسِيئُ الْجِوَارَ يَأْكُلُ الْقَوِيُّ مِنَّا الضَّعِيفَ فَكُنَّا عَلَى ذَلِكَ حَتَّى بَعَثَ اللَّهُ إِلَيْنَا رَسُولًا مِنَّا نَعْرِفُ نَسَبَهُ وَصِدْقَهُ وَأَمَانَتَهُ وَعَفَافَهُ فَدَعَانَا إِلَى اللَّهِ تَعَالَى لِنُوَحِّدَهُ وَنَعْبُدَهُ وَنَخْلَعَ مَا كُنَّا نَعْبُدُ نَحْنُ وَآبَاؤُنَا مِنْ دُونِهِ مِنْ الْحِجَارَةِ وَالْأَوْثَانِ وَأَمَرَ بِصِدْقِ الْحَدِيثِ وَأَدَاءِ الْأَمَانَةِ وَصِلَةِ الرَّحِمِ وَحُسْنِ الْجِوَارِ وَالْكَفِّ عَنْ الْمَحَارِمِ وَالدِّمَاءِ وَنَهَانَا عَنْ الْفَوَاحِشِ وَقَوْلِ الزُّورِ وَأَكْلِ مَالِ الْيَتِيمِ وَقَذْفِ الْمُحْصَنَةِ وَأَمَرَنَا أَنْ نَعْبُدَ اللَّهَ وَحْدَهُ لَا نُشْرِكُ بِهِ شَيْئًا وَأَمَرَنَا بِالصَّلَاةِ وَالزَّكَاةِ وَالصِّيَامِ قَالَ فَعَدَّدَ عَلَيْهِ أُمُورَ الْإِسْلَامِ فَصَدَّقْنَاهُ وَآمَنَّا بِهِ وَاتَّبَعْنَاهُ عَلَى مَا جَاءَ بِهِ فَعَبَدْنَا اللَّهَ وَحْدَهُ فَلَمْ نُشْرِكْ بِهِ شَيْئًا وَحَرَّمْنَا مَا حَرَّمَ عَلَيْنَا وَأَحْلَلْنَا مَا أَحَلَّ لَنَا فَعَدَا عَلَيْنَا قَوْمُنَا فَعَذَّبُونَا فَفَتَنُونَا عَنْ دِينِنَا لِيَرُدُّونَا إِلَى عِبَادَةِ الْأَوْثَانِ مِنْ عِبَادَةِ اللَّهِ وَأَنْ نَسْتَحِلَّ مَا كُنَّا نَسْتَحِلُّ مِنْ الْخَبَائِثِ وَلَمَّا قَهَرُونَا وَظَلَمُونَا وَشَقُّوا عَلَيْنَا وَحَالُوا بَيْنَنَا وَبَيْنَ دِينِنَا خَرَجْنَا إِلَى بَلَدِكَ وَاخْتَرْنَاكَ عَلَى مَنْ سِوَاكَ وَرَغِبْنَا فِي جِوَارِكَ وَرَجَوْنَا أَنْ لَا نُظْلَمَ عِنْدَكَ أَيُّهَا الْمَلِكُ قَالَتْ فَقَالَ لَهُ النَّجَاشِيُّ هَلْ مَعَكَ مِمَّا جَاءَ بِهِ عَنْ اللَّهِ مِنْ شَيْءٍ قَالَتْ فَقَالَ لَهُ جَعْفَرٌ نَعَمْ فَقَالَ لَهُ النَّجَاشِيُّ فَاقْرَأْهُ عَلَيَّ فَقَرَأَ عَلَيْهِ صَدْرًا مِنْ كهيعص قَالَتْ فَبَكَى وَاللَّهِ النَّجَاشِيُّ حَتَّى أَخْضَلَ لِحْيَتَهُ وَبَكَتْ أَسَاقِفَتُهُ حَتَّى أَخْضَلُوا مَصَاحِفَهُمْ حِينَ سَمِعُوا مَا تَلَا عَلَيْهِمْ ثُمَّ قَالَ النَّجَاشِيُّ إِنَّ هَذَا وَالَّذِي جَاءَ بِهِ مُوسَى لَيَخْرُجُ مِنْ مِشْكَاةٍ وَاحِدَةٍ انْطَلِقَا فَوَاللَّهِ لَا أُسْلِمُهُمْ إِلَيْكُمْ أَبَدًا وَلَا أَكَادُ قَالَتْ أُمُّ سَلَمَةَ رَضِيَ اللَّهُ عَنْهَا فَلَمَّا خَرَجَا مِنْ عِنْدِهِ قَالَ عَمْرُو بْنُ الْعَاصِ وَاللَّهِ لَآتِيَنَّهُ غَدًا أَعِيبُهُمْ عِنْدَهُ ثُمَّ أَسْتَأْصِلُ بِهِ خَضْرَاءَهُمْ قَالَتْ فَقَالَ لَهُ عَبْدُ اللَّهِ بْنُ أَبِي رَبِيعَةَ وَكَانَ أَتْقَى الرَّجُلَيْنِ فِينَا لَا تَفْعَلْ فَإِنَّ لَهُمْ أَرْحَامًا وَإِنْ كَانُوا قَدْ خَالَفُونَا قَالَ وَاللَّهِ لَأُخْبِرَنَّهُ أَنَّهُمْ يَزْعُمُونَ أَنَّ عِيسَى ابْنَ مَرْيَمَ عَلَيْهِمَا السَّلَام عَبْدٌ قَالَتْ ثُمَّ غَدَا عَلَيْهِ الْغَدَ فَقَالَ لَهُ أَيُّهَا الْمَلِكُ إِنَّهُمْ يَقُولُونَ فِي عِيسَى ابْنِ مَرْيَمَ قَوْلًا عَظِيمًا فَأَرْسِلْ إِلَيْهِمْ فَسَلْهُمْ عَمَّا يَقُولُونَ فِيهِ قَالَتْ أُمُّ سَلَمَةَ فَأَرْسَلَ إِلَيْهِمْ يَسْأَلُهُمْ عَنْهُ قَالَتْ وَلَمْ يَنْزِلْ بِنَا مِثْلُهَا فَاجْتَمَعَ الْقَوْمُ فَقَالَ بَعْضُهُمْ لِبَعْضٍ مَاذَا تَقُولُونَ فِي عِيسَى إِذَا سَأَلَكُمْ عَنْهُ قَالُوا نَقُولُ وَاللَّهِ فِيهِ مَا قَالَ اللَّهُ سُبْحَانَهُ وَتَعَالَى وَمَا جَاءَ بِهِ نَبِيُّنَا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَائِنًا فِي ذَلِكَ مَا هُوَ كَائِنٌ فَلَمَّا دَخَلُوا عَلَيْهِ قَالَ لَهُمْ مَا تَقُولُونَ فِي عِيسَى ابْنِ مَرْيَمَ فَقَالَ لَهُ جَعْفَرُ بْنُ أَبِي طَالِبٍ رَضِيَ اللَّهُ عَنْهُ نَقُولُ فِيهِ الَّذِي جَاءَ بِهِ نَبِيُّنَا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هُوَ عَبْدُ اللَّهِ وَرَسُولُهُ وَرُوحُهُ وَكَلِمَتُهُ أَلْقَاهَا إِلَى مَرْيَمَ الْعَذْرَاءِ الْبَتُولِ قَالَتْ فَضَرَبَ النَّجَاشِيُّ يَدَهُ عَلَى الْأَرْضِ فَأَخَذَ مِنْهَا عُودًا ثُمَّ قَالَ مَا عَدَا عِيسَى ابْنُ مَرْيَمَ مَا قُلْتَ هَذَا الْعُودَ فَنَاخَرَتْ بَطَارِقَتُهُ حَوْلَهُ حِينَ قَالَ مَا قَالَ فَقَالَ وَإِنْ نَخَرْتُمْ وَاللَّهِ اذْهَبُوا فَأَنْتُمْ سُيُومٌ بِأَرْضِي وَالسُّيُومُ الْآمِنُونَ مَنْ سَبَّكُمْ غَرِمَ ثُمَّ مَنْ سَبَّكُمْ غَرِمَ ثُمَّ مَنْ سَبَّكُمْ غَرِمَ فَمَا أُحِبُّ أَنَّ لِي دَبْرَ ذَهَبٍ وَأَنِّي آذَيْتُ رَجُلًا مِنْكُمْ وَالدَّبْرُ بِلِسَانِ الْحَبَشَةِ الْجَبَلُ رُدُّوا عَلَيْهِمَا هَدَايَاهُمَا فَلَا حَاجَةَ لَنَا بِهَا فَوَاللَّهِ مَا أَخَذَ اللَّهُ مِنِّي الرِّشْوَةَ حِينَ رَدَّ عَلَيَّ مُلْكِي فَآخُذَ الرِّشْوَةَ فِيهِ وَمَا أَطَاعَ فِيَّ النَّاسَ فَأُطِيعَهُمْ فِيهِ قَالَتْ فَخَرَجَا مِنْ عِنْدِهِ مَقْبُوحَيْنِ مَرْدُودًا عَلَيْهِمَا مَا جَاءَا بِهِ وَأَقَمْنَا عِنْدَهُ بِخَيْرِ دَارٍ مَعَ خَيْرِ جَارٍ قَالَتْ فَوَاللَّهِ إِنَّا عَلَى ذَلِكَ إِذْ نَزَلَ بِهِ يَعْنِي مَنْ يُنَازِعُهُ فِي مُلْكِهِ قَالَتْ فَوَاللَّهِ مَا عَلِمْنَا حُزْنًا قَطُّ كَانَ أَشَدَّ مِنْ حُزْنٍ حَزِنَّاهُ عِنْدَ ذَلِكَ تَخَوُّفًا أَنْ يَظْهَرَ ذَلِكَ عَلَى النَّجَاشِيِّ فَيَأْتِيَ رَجُلٌ لَا يَعْرِفُ مِنْ حَقِّنَا مَا كَانَ النَّجَاشِيُّ يَعْرِفُ مِنْهُ قَالَتْ وَسَارَ النَّجَاشِيُّ وَبَيْنَهُمَا عُرْضُ النِّيلِ قَالَ فَق","trj":"Telah menceritakan kepada kami [Ya'qub] telah menceritakan kepada kami [ayahku] dari [Muhammad bin Ishaq] telah menceritakan kepadaku [Muhammad bin Muslim bin 'Abdullah bin Syihab] dari [Abu Bakr bin 'Abdur Rahman bin Al Harits bin Hisyam Al Makhzumi] dari [Ummu Salamah binti Abu Umaiyah bin Al Mughirah istri Nabi Shallallahu'alaihiwasallam] berkata; Saat kami tinggal ditanah Habasyah dan kami tinggal bersama tetangga yang baik An Najasy, ia memberi jaminan keamanan atas agama kami, kami menyembah Allah subhanahu wata'ala, kami tidak diganggu dan kami tidak mendengar sesuatu pun yang tidak kami sukai. Saat hal itu terdengar oleh kaum Quraisy, mereka bersekongkol untuk mengutus dua orang kuat untuk menemui An Najasy tentang kami dan memberi hadiah barang Mekkah yang paling menakjubkan. Ketika itu, barang yang paling menakjubkan baginya adalah kulit yang disamak buatan Makkah. Maka mereka kumpulkan sebanyak-banyaknya. Tidaklah mereka tinggalkan satu pun panglima pasukan Najasyi melainkan pasti diberinya hadiah. Orang yang ditugasi Quraisy untuk mengirim hadiah-hadiah ini adalah 'Abdullah bin Rabi'ah bin Al Mughirah Al Makhzumi dan 'Amr bin Al 'Ash bin Wa`il As Sahmi. Mereka limpahkan kepentingan mereka kepada dua orang ini, seraya mereka katakan kepada keduanya; 'Tolong, serahkan hadiah kepada setiap komandan pasukan sebelum kalian berbicara dengan An Najasy ditengah-tengah mereka, setelah itu serahkan hadiah untuk An Najasy. Dan mintalah dia agar menyerahkankan orang-orang muslim itu kepada kalian berdua sebelum dia mengajak bicara mereka. (Ummu Salamah) mengatakan; Kami tinggal dan bertetangga baik dengannya. Tidak ada satu pun komandan Najasyi melainkan pasti diberi hadiah oleh keduanya sebelum keduanya berbicara dengan An Najasy, kemudian berkata kepada semua petinggi-petinggi Negara saat itu; Sesungguhnya orang-orang tolol kami telah datang ke negeri sang raja, mereka meninggalkan agama mereka dan mereka tidak masuk ke dalam agama kalian, mereka membawa agama baru yang sama-sama tidak kami dan kalian kenal. Para pembesar mereka mengutus kami kepada sang raja agar mengembalikan mereka. Bila kami berbicara dengan sang raja tentang mereka, berisyaratlah kalian kepadanya agar menyerahkan mereka kepada kami dan jangan sampai sang raja mengajak berbicara dengan mereka karena mereka lebih tahu terhadap satu persatu diantara mereka dan kekurangan-kekurangan mereka. Para petinggi Najasyi berkata kepada keduanya; Baik. Selanjutnya keduanya menyerahkan hadiah-hadiah kepada An Najasy lalu diterima dari keduanya. Selanjutnya mereka berdua berbicara pada An Najasy; Wahai raja! Sesungguhnya orang-orang tolol kami kami telah mendatangi negeri raja, mereka meninggalkan agama kaum mereka dan tidak mau masuk ke dalam agamamu, mereka membawa agama baru yang tidak kami kenal dan tidak juga engkau. Para pembesar kaum mereka, ayah-ayah mereka, paman-paman mereka, dan kelompok-kelompok mereka mengutus kami dengan tujuan agar baginda raja mau mengembalikan mereka. Yang demikian karena mereka lebih tahu terhadap satu persatu diantara mereka dan tahu borok-borok kekurangan dan aib mereka. Berkata Ummu Salamah; Dan sebenarnya tidak ada sesuatu hal yang lebih dibenci oleh 'Abdullah bin Abu Robi'ah dan 'Amr bin Al 'Ash daripada jika An Najasy mau mendengar keluh kesah mereka. Para petinggi negara di sekitar raja lantas berkata; Utusan ini benar, wahai raja. Kaum mereka lebih tahu perihal kejelekan-kejelekan mereka, maka serahkan saja mereka kepada keduanya untuk dikembalikan ke negeri dan kaum mereka. Ternyata raja An Najasy justeru marah atas celaan yang mereka lancarkan lalu berkata; 'Tidak demi Allah, sekali-kali aku tidak akan menyerahkan mereka kepada keduanya. Tidak bakalan aku melakukan tindak kejahatan kepada suatu kaum yang bertetangga denganku, tinggal dinegeriku dan memilihku dari selainku, hingga aku memanggil mereka dan menanyakan mereka tentang perkataan kedua utusan ini mengenai mereka. Bila mereka seperti yang dikatakan oleh kedua utusan ini, akan kuserahkan mereka kepada keduanya dan akan kukembalikan kepada kaum mereka. Sebaliknya bila tidak, maka aku melindungi mereka dari kedua orang ini dan aku akan bertetangga baik dengan mereka selama mereka bertetangga baik denganku. Berkata Ummu Salamah; Kemudian An Najasy mengirim utusan untuk menemui sahabat-sahabat Rasulullah Shallallahu'alaihiWasallam dan memanggil mereka. Saat utusan An Najasy datang, para sahabat muslimin berkumpul dan saling berkata satu sama lain; Bagaimana pendapat kalian tentang orang itu bila kalian menemuinya?. Mereka menjawab; Demi Allah, Kita mengatakan terus terang apa yang kita ketahui, dan yang Nabi Shallallahu'alaihiWasallam perintahkan kepada kita dan terjadilah segala yang terjadi. Saat utusan itu kembali menemui An Najasy, An Najasy telah memanggil uskup-uskupnya, dan menyebarkan kitab suci mereka disekitar An Najasy untuk menanyai para sahabat muslimin. Raja Najasy bertanya; 'Tolong jelaskan agama yang kalian anut, yang karenanya kalian kalian berpisah dengan kaum kalian dan kalian tidak mau masuk ke dalam agamaku, tidak juga kepada satu pun agama yang dianut manusia? Berkata Ummu Salamah; Yang tampil menjawab pertanyaan raja adalah [Ja'far bin bu Thalib]. Ia berkata kepada An Najasy; 'Wahai raja! Dulunya kami kaum jahiliyah, kami dulu menyembah berhala, gemar makan bangkai, melakukan tindakan-tindakan keji, memutuskan tali sillaturrahim, bersikap buruk terhadap tetangga, yang kuat mencaplok yang lemah dan kami berada dalam kondisi seperti itu hingga Allah mengutus seorang rasul dari kalangan kami, kami mengenal nasab, kejujuran dan keamanahannya. Ia menyerukan kami kepada Allah Subhanahu wa ta'ala untuk kami esakan, kami sembah dan kami lepaskan apa pun yang kami dan nenek moyang kami sembah selain Allah seperti batu dan berhala, ia memerintahkan kami agar berbicara dengan jujur, menunaikan amanah, menyambung tali sillaturrahim, bersikap baik terhadap tetangga, menjaga diri dari keharaman, memerintahkan kami agar berdoa dan melarang kami dari perbuatan-perbuatan keji, berkata dusta, memakan harta anak yatim, menuduh wanita bersuami berzina, memerintahkan kami untuk menyembah Allah semata, tidak menyekutukannya dengan apa pun, memerintahkan kami agar menunaikan shalat, zakat dan berpuasa. Ia menyebarkan ajaran-ajaran Islam, kami mempercayai dan mengimaninya, kami mengikuti ajaran yang ia bawa, kami menyembah Allah semata dan tidak menyekutukanNya dengan apa pun, kami mengharamkan yang diharamkan pada kami dan menghalalkan yang dihalalkan bagi kami lalu kaum kami memusuhi kami, mereka menyiksa dan menimpakan ujian pada kami karena masalah agama kami agar mereka mengembalikan kami menyembah berhala lagi selain Allah, menghalalkan kekejian-kekejian yang dulu pernah kami lakukan. Saat mereka memaksa kami, menzhalimi kami dan memecah kami, mereka menghalangi kami untuk menjalankan agama kami akhirnya kami pergi ke negerimu, kami lebih memilihmu atas selainmu, kami ingin bertetangga denganmu dan kami harap engkau tidak mendzalimi kami wahai raja. Berkata Ummu Salamah; An Najasy berkata padanya; Mungkin kalian bisa membacakan yang Rasulullah terima dari Allah? Ja'far menjawab; Ya. An Najasy berkata; Bacalah. Kemudian Ja'far membaca permulaan surat Maryam lalu An Najasy menangis, demi Allah, sampai membasahi jenggotnya, dan uskup-uskupnya pun menangis hingga membasahi kitab suci-kitab suci mereka saat mendengar yang dibacakan Ja'far kepada mereka. Kemudian An Najasy berkomentar; Sesungguhnya ini demi yang dibawa Musa, berasal dari lentera yang sama. Demi Allah, aku tidak bakalan menyerahkan mereka kepada kalian dan tidak akan berbuat yang tidak-tidak untuk mereka. Berkata Ummu Salamah; Saat keduanya keluar meninggalkan An Najasy, berkata 'Amr bin Al 'Ash; 'Demi Allah, aku akan mendatanginya lagi besok, dan akan kucela mereka didekatnya, kemudian mereka akan aku habisi hingga ke akar-akarnya. Berkata Ummu Salamah; 'Abdullah bin Abu Robi'ah, orang yang paling menahan diri diantara dua orang itu bagi kami berkata padanya; 'Jangan kau lakukan karena mereka memiliki kerabat meski mereka berselisih dengan kami.' 'Amru bin 'Ash mengatakan; 'Demi Allah, akan kuberitahu mereka bahwa mereka menilai 'Isa putra Maryam adalah seorang hamba.' Berkata Ummu Salamah; Kemudian 'Amr pergi di keesokan harinya lalu berkata kepada An Najasy; Wahai raja! Sesungguhnya mereka mengemukakan komentar yang lancang tentang 'Isa putra Maryam. Utuslah seseorang untuk menemui mereka dan tanyakan kepada mereka bagaimana pendapat mereka tentang 'Isa. Berkata Ummu Salamah; An Najasy mengirim utusan untuk menanyakan pandangan mereka tentang 'Isa. Kaum muslimin berkumpul lalu sebagaian dari mereka berkata kepada yang lain; Apa yang akan kalian katakan tentang 'Isa bila raja bertanya pada kalian. Mereka berkata; Demi Allah, akan kami katakan seperti yang difirmankan Allah subhanahu wata'ala tentangnya dan yang dibawa oleh Nabi Shallallahu'alaihiWasallam tentang hal itu bagaimana pun juga. Saat kaum muslimin mendatangi An Najasy, ia bertanya pada mereka; Bagaimana pandangan kalian tentang 'Isa putra Maryam? Ja'far bin Abu Thalib Radliyallahu'anhu menjawab; Pendapat kami seperti yang disampaikan Nabi kami, dia adalah hamba dan rasul Allah, ruh dan kalimatNya yang disematkan kepada Maryam, perawan suci. Berkata Ummu Salamah; An Najasy memukulkan tangannya ke tanah lalu mengambil sebilah kayu dan berkata; Selain 'Isa putra Maryam, bagaimana pendapatmu tentang kayu ini?. Para petinggi kerajaan lantas berbincang-bincang tentang suatu hal yang tak bisa dimengerti. Lantas raja berkata; Kendatipun kalian wahai petinggi kerajaanku masih berbincang-bincang, pergilah kalian dengan aman wahai muslimin di tanahku, siapa pun yang menawan kalian dia harus mengganti jaminan, siapa pun yang menawan kalian harus mengganti jaminan, siapa pun yang menawan kalian harus mengganti jaminan. Aku tidak mau memiliki segunung emas sementara aku menyakiti salah seorang dari kalian. Kembalikan hadiah mereka berdua, kami tidak memerlukannya. Demi Allah, Allah tidak mengambil suap dariku saat mengembalikan kerajaanku kepadaku lalu bagaimana mungkin aku mengambilnya? Dan tidaklah mungkin manusia yang Allah jadikan taat kepadaku, lalu aku langsung taat begitu saja kepada mereka. Berkata Ummu Salamah; Keduanya pergi meninggalkannya dengan menanggung malu dan tertolak tujuannya. Kami tinggal dinegerinya dengan baik dan bersama tetangga yang baik. Demi Allah, kami terus seperti itu hingga ada yang menentangnya dalam kekuasaannya. Demi Allah, kami tidak mengetahui kesedihan yang lebih besar dari kesedihan yang menimpa kami saat itu karena kami khawatir muncul raja baru yang tidak mengenal hak kami seperti yang dikenali oleh An Najasy. Berkata Ummu Salamah; An Najasy berjalan dan diantara keduanya ada lembah sungai Nil. Kemudian para sahabat Rasulullah Shallallahu'alaihiWasallam berkata; Siapa yang mau pergi untuk menghadiri peristiwa yang terjadi lalu datang membawa khabar untuk kami. Berkata Ummu Salamah; Berkata Az Zubair bin Al 'Awwam Radliyallahu'anhu; Aku. Dan ia yang paling muda diantara kami. Mereka meniup geriba untuknya lalu diletakkan didada lalu berenang hingga ke tepi sungai Nil tempat bertemunya kaum. Ia pergi hingga mendatangi mereka dan kami berdoa kepada Allah subhanahu wata'ala untuk An Najasy agar mengalahkan musuhnya, kembali berkuasa diatas negerinya dan urusan rakyat Habasyah menguat. Kami tinggal ditempat terbaik disisinya hingga kami mendatangi Rasulullah Shallallahu'alaihiWasallam saat beliau di Mekah."},{"p":"Ahmad","n":3885,"ar":"حَدَّثَنَا ابْنُ إِدْرِيسَ قَالَ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرٍ عَنْ أُمِّ مُبَشِّرٍ امْرَأَةِ زَيْدِ بْنِ حَارِثَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَيْتِ حَفْصَةَ فَقَالَ لَا يَدْخُلُ النَّارَ أَحَدٌ شَهِدَ بَدْرًا وَالْحُدَيْبِيَةَ قَالَتْ حَفْصَةُ أَلَيْسَ اللَّهُ عَزَّ وَجَلَّ يَقُولُ{ وَإِنْ مِنْكُمْ إِلَّا وَارِدُهَا }قَالَتْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَهْ{ ثُمَّ نُنَجِّي الَّذِينَ اتَّقَوْا }","trj":"Telah menceritakan kepada kami [Ibnu Idris] berkata, telah menceritakan kepada kami [Al A'masy] dari [Abu Sufyan] dari [Jabir] dari [Ummu Mubasyir] isteri Zaid bin Haritsah, ia berkata, \"Saat Rasulullah shallallahu 'alaihi wasallam berada di rumah Hafshah, beliau bersabda: \"Tidak akan masuk neraka seseorang yang mengikuti perang Badar dan Hudaibiyah.\" Hafshah berkata, \"Bukankah Allah Azza Wa Jalla berfirman: '(Dan tidak ada seorangpun dari padamu, melainkan mendatangi neraka itu) ' (Qs. Maryam: 71). Rasulullah shallallahu 'alaihi wasallam lalu bersabda: \"Lalu bagaimana dengan firman Allah Ta'ala: '(Kemudian kami akan menyelamatkan orang-orang yang bertakwa) ' (Qs. Maryam: 72)."},{"p":"Ahmad","n":4148,"ar":"حَدَّثَنَا حَجَّاجٌ قَالَ أَخْبَرَنِي ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي أَبُو الزُّبَيْرِ أَنَّهُ سَمِعَ جَابِرًا قَالَ حَدَّثَتْنِي أُمُّ مُبَشِّرٍ أَنَّهاسَمِعَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِنْدَ حَفْصَةَ يَقُولُ لَا يَدْخُلُ النَّارَ إِنْ شَاءَ اللَّهُ مِنْ أَصْحَابِ الشَّجَرَةِ أَحَدٌ الَّذِينَ بَايَعُوا تَحْتَهَا فَقَالَتْ بَلَى يَا رَسُولَ اللَّهِ فَانْتَهَرَهَا فَقَالَتْ حَفْصَةُ{ وَإِنْ مِنْكُمْ إِلَّا وَارِدُهَا }فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ قَالَ اللَّهُ عَزَّ وَجَلَّ{ ثُمَّ نُنَجِّي الَّذِينَ اتَّقَوْا وَنَذَرُ الظَّالِمِينَ فِيهَا جِثِيًّا }","trj":"Telah menceritakan kepada kami [Hajjaj] dia berkata, telah mengabarkan kepadaku [Ibnu Juraij] berkata; telah mengabarkan kepadaku [Abu Zubair] bahwa dia mendengar [Jabir] berkata, telah menceritakan kepadaku [Ummu Mubasyir] bahwa dia mendengar Rasulullah shallallahu 'alaihi wasallam waktu berada di samping Hafshah, beliau bersabda: \"Insyaallah tidak akan masuk Neraka orang-orang yang pernah berbaiat di bawah pohon.\" Hafshah berkata, \"Tentu wahai Rasulullah, \" namun beliau menghardiknya hingga Hafshah pun membaca: '(Dan tidak ada seorang pun dari padamu, melainkan mendatangi neraka itu) ' (Qs. Maryam: 71), lantas Nabi shallallahu 'alaihi wasallam bersabda: \"Sungguh Allah Azza Wa Jalla telah berfirman: '(Kemudian Kami akan menyelamatkan orang-orang yang bertakwa dan membiarkan orang-orang yang lalim di dalam neraka dalam keadaan berlutut) ' (Qs. Maryam: 72)."},{"p":"Bukhari","n":732,"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنَا أَيُّوبُ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَقَرَأَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيمَا أُمِرَ وَسَكَتَ فِيمَا أُمِرَ{ وَمَا كَانَ رَبُّكَ نَسِيًّا }{ لَقَدْ كَانَ لَكُمْ فِي رَسُولِ اللَّهِ أُسْوَةٌ حَسَنَةٌ }","trj":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Isma'il] berkata, telah menceritakan kepada kami [Ayyub] dari ['Ikrimah] dari [Ibnu 'Abbas] berkata, \"Nabi shallallahu 'alaihi wasallam membaca (dengan suara dikeraskan) sesuai apa yang diperintahkan dan juga diam (tidak mengeraskan) sesuai apa yang diperintahkan '(Dan tidaklah Rabbmu lupa) ' (Qs. Maryam: 64). '(Sesungguhnya telah ada pada diri Rasulullah itu suri teladan yang baik bagimu) ' (Qs. Al Ahzab: 21)."},{"p":"Bukhari","n":1173,"ar":"حَدَّثَنَا عَلِيٌّ حَدَّثَنَا سُفْيَانُ قَالَ سَمِعْتُ الزُّهْرِيَّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَمُوتُ لِمُسْلِمٍ ثَلَاثَةٌ مِنْ الْوَلَدِ فَيَلِجَ النَّارَ إِلَّا تَحِلَّةَ الْقَسَمِقَالَ أَبُو عَبْد اللَّهِ{ وَإِنْ مِنْكُمْ إِلَّا وَارِدُهَا }","trj":"Telah menceritakan kepada kami ['Ali] telah menceritakan kepada kami [Sufyan] berkata; aku mendengar [Az Zuhriy] dari [Sa'id bin Al Musayyab] dari [Abu Hurairah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Seorang muslim yang ditinggal wafat oleh tiga orang anaknya, tidak bakalan masuki neraka selain sebatas melakukan sumpah Allah\". Berkata, Abu 'Abdullah: Maksudnya melakukan sumpah Allah yang tersebut dalam Firman-Nya yang artinya; \"Tidaklah dari kalian melainkan pasti akan melewatinya (neraka) (QS. Maryam 71) \". "},{"p":"Bukhari","n":1949,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ شُعْبَةَ عَنْ سُلَيْمَانَ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ عَنْ خَبَّابٍ قَالَكُنْتُ قَيْنًا فِي الْجَاهِلِيَّةِ وَكَانَ لِي عَلَى الْعَاصِ بْنِ وَائِلٍ دَيْنٌ فَأَتَيْتُهُ أَتَقَاضَاهُ قَالَ لَا أُعْطِيكَ حَتَّى تَكْفُرَ بِمُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ لَا أَكْفُرُ حَتَّى يُمِيتَكَ اللَّهُ ثُمَّ تُبْعَثَ قَالَ دَعْنِي حَتَّى أَمُوتَ وَأُبْعَثَ فَسَأُوتَى مَالًا وَوَلَدًا فَأَقْضِيكَ فَنَزَلَتْ{ أَفَرَأَيْتَ الَّذِي كَفَرَ بِآيَاتِنَا وَقَالَ لَأُوتَيَنَّ مَالًا وَوَلَدًا أَطَّلَعَ الْغَيْبَ أَمْ اتَّخَذَ عِنْدَ الرَّحْمَنِ عَهْدًا }","trj":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Ibnu Abu 'Adiy] dari [Syu'bah] dari [Sulaiman] dari [Abu Adh-Dhuha] dari [Masruq] dari [Khabbab] berkata: \"Pada masa Jahiliyyah aku adalah seorang tukang besi dan emas dan Al 'Ash bin Wa'il pernah punya hutang kepadaku lalu aku datang menemuinya untuk menagihnya. Dia berkata: \"Aku tidak akan bayar kecuali kamu mau mengingkari (kufur) Muhammad shallallahu 'alaihi wasallam \". Aku katakan: \"Aku tidak akan kufur sampai kamu dimatikan oleh Allah Ta'ala lalu kamu dibangkitkan. Dia berkata: \"Biarkanlah aku sampai aku mati lalu dibangkitkan dan aku diberikan harta dan anak lalu aku bayar hutangku kepadamu\". Maka turunlah QS Maryam ayat 49 yang artinya: (\" Maka apakah kamu telah melihat orang yang kafir kepada ayat-ayat kami dan ia mengatakan: \"Pasti Aku akan diberi harta dan anak\". Adakah ia melihat yang ghaib atau ia telah membuat perjanjian di sisi Tuhan yang Maha Pemurah?\")."},{"p":"Bukhari","n":2114,"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ عَنْ مُسْلِمٍ عَنْ مَسْرُوقٍ حَدَّثَنَا خَبَّابٌ قَالَكُنْتُ رَجُلًا قَيْنًا فَعَمِلْتُ لِلْعَاصِ بْنِ وَائِلٍ فَاجْتَمَعَ لِي عِنْدَهُ فَأَتَيْتُهُ أَتَقَاضَاهُ فَقَالَ لَا وَاللَّهِ لَا أَقْضِيكَ حَتَّى تَكْفُرَ بِمُحَمَّدٍ فَقُلْتُ أَمَا وَاللَّهِ حَتَّى تَمُوتَ ثُمَّ تُبْعَثَ فَلَا قَالَ وَإِنِّي لَمَيِّتٌ ثُمَّ مَبْعُوثٌ قُلْتُ نَعَمْ قَالَ فَإِنَّهُ سَيَكُونُ لِي ثَمَّ مَالٌ وَوَلَدٌ فَأَقْضِيكَ فَأَنْزَلَ اللَّهُ تَعَالَى{ أَفَرَأَيْتَ الَّذِي كَفَرَ بِآيَاتِنَا وَقَالَ لَأُوتَيَنَّ مَالًا وَوَلَدًا }","trj":"Telah menceritakan kepada kami ['Umar bin Hafsh] telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Al A'masy] dari [Muslim] dari [Masruq] telah menceritakan kepada kami [Khabbab] berkata: \"Pada masa Jahiliyyah aku adalah seorang tukang besi dan emas lalu aku bekerja pada Al 'Ash bin Wa'il lalu upahku aku kumpulkan kepadanya kemudian aku menagih agar dia membayarnya. Dia berkata: \"Demi Allah, aku tidak akan membayarnya kepadamu kecuali kamu mau mengingkari (kufur) Muhammad shallallahu 'alaihi wasallam \". Aku katakan: \"Adapun aku, demi Allah tidak akan kufur sampai kamu mati lalu kamu dibangkitkan. Dia berkata: \"Biarkanlah aku sampai aku mati lalu dibangkitkan\". Aku katakan: Baik kalau begitu\". Dia berkata: \"Sungguh aku akan mendapatkan harta dan anak lalu aku akan bayar hutang kepadamu\". Maka Allah Ta'ala menurunkan QS Maryam ayat yang artinya: (\" Maka apakah kamu telah melihat orang yang kafir kepada ayat-ayat kami dan ia mengatakan \"pasti Aku akan diberi harta dan anak\") (QS. Maryam 77)."},{"p":"Bukhari","n":2247,"ar":"حَدَّثَنَا إِسْحَاقُ حَدَّثَنَا وَهْبُ بْنُ جَرِيرِ بْنِ حَازِمٍ أَخْبَرَنَا شُعْبَةُ عَنْ الْأَعْمَشِ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ عَنْ خَبَّابٍ قَالَكُنْتُ قَيْنًا فِي الْجَاهِلِيَّةِ وَكَانَ لِي عَلَى الْعَاصِ بْنِ وَائِلٍ دَرَاهِمُ فَأَتَيْتُهُ أَتَقَاضَاهُ فَقَالَ لَا أَقْضِيكَ حَتَّى تَكْفُرَ بِمُحَمَّدٍ فَقُلْتُ لَا وَاللَّهِ لَا أَكْفُرُ بِمُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى يُمِيتَكَ اللَّهُ ثُمَّ يَبْعَثَكَ قَالَ فَدَعْنِي حَتَّى أَمُوتَ ثُمَّ أُبْعَثَ فَأُوتَى مَالًا وَوَلَدًا ثُمَّ أَقْضِيَكَ فَنَزَلَتْ{ أَفَرَأَيْتَ الَّذِي كَفَرَ بِآيَاتِنَا وَقَالَ لَأُوتَيَنَّ مَالًا وَوَلَدًا }الْآيَةَ","trj":"Telah menceritakan kepada kami [Ishaq] telah menceritakan kepada kami [Wahb bin Jarir bin Hazim] telah mengabarkan kepada kami [Syu'bah] dari [Al A'masy] dari [Abu Adh Dhuha] dari [Masruq] dari [Khabbab] berkata: \"Pada masa Jahiliyyah aku adalah seorang tukang besi dan aku punya uang dirham yang ada pada Al 'Ash bin Wa'il lalu aku menemui dia untuk menagih agar dia membayarnya. Dia berkata: \"Aku tidak akan membayarnya kepadamu kecuali kamu mau mengingkari (kufur) Muhammad shallallahu 'alaihi wasallam \". Aku katakan: \"Demi Allah, aku tidak akan kufur kepada Muhammad shallallahu 'alaihi wasallam sampai Allah mematikan kamu lalu kamu dibangkitkan. Dia berkata: \"Biarkanlah sampai aku mati lalu dibangkitkan dan disana aku akan mendapatkan harta dan anak lalu aku akan bayar hutang kepadamu\". Maka Allah Ta'ala menurunkan QS Maryam ayat yang artinya: (\" Maka apakah kamu telah melihat orang yang kafir kepada ayat-ayat kami dan ia mengatakan \"pasti aku akan diberi harta dan anak\" (QS. Maryam 77)."},{"p":"Bukhari","n":3762,"ar":"حَدَّثَنَا عَبْدَانُ عَنْ أَبِي حَمْزَةَ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ قَالَكُنَّا جُلُوسًا مَعَ ابْنِ مَسْعُودٍ فَجَاءَ خَبَّابٌ فَقَالَ يَا أَبَا عَبْدِ الرَّحْمَنِ أَيَسْتَطِيعُ هَؤُلَاءِ الشَّبَابُ أَنْ يَقْرَءُوا كَمَا تَقْرَأُ قَالَ أَمَا إِنَّكَ لَوْ شِئْتَ أَمَرْتُ بَعْضَهُمْ يَقْرَأُ عَلَيْكَ قَالَ أَجَلْ قَالَ اقْرَأْ يَا عَلْقَمَةُ فَقَالَ زَيْدُ بْنُ حُدَيْرٍ أَخُو زِيَادِ بْنِ حُدَيْرٍ أَتَأْمُرُ عَلْقَمَةَ أَنْ يَقْرَأَ وَلَيْسَ بِأَقْرَئِنَا قَالَ أَمَا إِنَّكَ إِنْ شِئْتَ أَخْبَرْتُكَ بِمَا قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي قَوْمِكَ وَقَوْمِهِ فَقَرَأْتُ خَمْسِينَ آيَةً مِنْ سُورَةِ مَرْيَمَ فَقَالَ عَبْدُ اللَّهِ كَيْفَ تَرَى قَالَ قَدْ أَحْسَنَ قَالَ عَبْدُ اللَّهِ مَا أَقْرَأُ شَيْئًا إِلَّا وَهُوَ يَقْرَؤُهُ ثُمَّ الْتَفَتَ إِلَى خَبَّابٍ وَعَلَيْهِ خَاتَمٌ مِنْ ذَهَبٍ فَقَالَ أَلَمْ يَأْنِ لِهَذَا الْخَاتَمِ أَنْ يُلْقَى قَالَ أَمَا إِنَّكَ لَنْ تَرَاهُ عَلَيَّ بَعْدَ الْيَوْمِ فَأَلْقَاهُرَوَاهُ غُنْدَرٌ عَنْ شُعْبَةَ","trj":"Telah menceritakan kepada kami ['Abdan] dari [Abu Hamzah] dari [Al A'masy] dari [Ibrahim] dari ['Alqamah] dia berkata; Kami pernah duduk-duduk bersama [Ibnu Mas'ud]. Tiba-tiba Khabab datang seraya berkata; 'Wahai Abu Abdurrahman, Apakah para pemuda itu bisa membaca sebagaimana anda membaca? Dia menjawab; Kalau kamu ingin, aku suruh sebagian dari mereka untuk membacakan kepadamu? Khabab menjawab; 'Ya.' Ibnu Mas'ud berkata; 'Wahai Alqamah, bacalah! ' maka Zaid bin Hudair -saudara Ziyad bin Hudair- berkata; 'Apakah engkau menyuruh Alqamah untuk membaca padahal dia bukanlah yang terbaik dari kami? Ibnu Mas'ud berkata; Jika kamu mau, akan saya beritahukan kepadamu sabda Nabi shallallahu 'alaihi wasallam mengenai kaummu dan kaumnya. Maka aku membacakan lima puluh ayat dari surat Maryam. Lalu Abdullah berkata; Apa pendapatmu? Zaid berkata; Sungguh bagus. Abdullah berkata; Aku tidak membaca sesuatu kecuali ia pun telah membacanya. Kemudian ia menoleh kepada Khabab ditangannya ada cincin dari emas. Lalu Abdullah berkata; kenapa cincin ini tidak dibuang saja? Khabab berkata; sesungguhnya kamu tidak akan melihatnya lagi ada padaku setelah hari ini. Lalu ia membuangnya. Diriwayatkan oleh [Ghundar] dari [Syu'bah]."},{"p":"Bukhari","n":4059,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ عَنْ خَبَّابٍ قَالَكُنْتُ قَيْنًا بِمَكَّةَ فَعَمِلْتُ لِلْعَاصِ بْنِ وَائِلٍ السَّهْمِيِّ سَيْفًا فَجِئْتُ أَتَقَاضَاهُ فَقَالَ لَا أُعْطِيكَ حَتَّى تَكْفُرَ بِمُحَمَّدٍ قُلْتُ لَا أَكْفُرُ بِمُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى يُمِيتَكَ اللَّهُ ثُمَّ يُحْيِيَكَ قَالَ إِذَا أَمَاتَنِي اللَّهُ ثُمَّ بَعَثَنِي وَلِي مَالٌ وَوَلَدٌ فَأَنْزَلَ اللَّهُ{ أَفَرَأَيْتَ الَّذِي كَفَرَ بِآيَاتِنَا وَقَالَ لَأُوتَيَنَّ مَالًا وَوَلَدًا أَطَّلَعَ الْغَيْبَ أَمْ اتَّخَذَ عِنْدَ الرَّحْمَنِ عَهْدًا }قَالَ مَوْثِقًالَمْ يَقُلْ الْأَشْجَعِيُّ عَنْ سُفْيَانَ سَيْفًا وَلَا مَوْثِقًا","trj":"Telah menceritakan kepada kami [Muhammad bin Katsir] Telah mengabarkan kepada kami [Sufyan] dari [Al A'masy] dari [Abu Adl Dluha] dari [Masruq] dari [Khabbab] dia berkata; \"Aku adalah seorang pandai besi di Makkah, dan aku membuatkan sebilah pedang untuk Al Ash bin Wa'il As Sahmi. Tatkala aku mendatanginya untuk menagih bayarannya, dia berkata; \"Aku tidak akan membayarkannya sampai kamu mendustakan Muhammad.\" Khabab berkata; \"Demi Allah, aku tidak akan mendustakan Muhammad shallallahu 'alaihi wasallam sampai kamu dimatikan Allah kemudian kamu dibangkitkan kembali.\" Al Ash bin Wa`il berkata; \"Kalau begitu tunggulah sampai aku mati dan dibangkitkan kembali hingga aku diberi harta dan anak, maka aku akan membayarmu. Maka turunlah ayat ini: 'Maka apakah kamu Telah melihat orang yang kafir kepada ayat-ayat kami dan ia mengatakan: \"Pasti Aku akan diberi harta dan anak. Adakah ia melihat yang ghaib atau ia telah membuat perjanjian di sisi Tuhan Yang Maha Pemurah?. (QS. Maryam: 77-78). Khabab berkata; Yaitu ikatan janji. Namun [Al Asyja'i] tidak menyebutkan lafazh 'saif' (pedang) dan 'Mautsiq' (perjanjian)."},{"p":"Bukhari","n":4060,"ar":"حَدَّثَنَا بِشْرُ بْنُ خَالِدٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ سُلَيْمَانَ سَمِعْتُ أَبَا الضُّحَى يُحَدِّثُ عَنْ مَسْرُوقٍ عَنْ خَبَّابٍ قَالَكُنْتُ قَيْنًا فِي الْجَاهِلِيَّةِ وَكَانَ لِي دَيْنٌ عَلَى الْعَاصِ بْنِ وَائِلٍ قَالَ فَأَتَاهُ يَتَقَاضَاهُ فَقَالَ لَا أُعْطِيكَ حَتَّى تَكْفُرَ بِمُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ وَاللَّهِ لَا أَكْفُرُ حَتَّى يُمِيتَكَ اللَّهُ ثُمَّ يَبْعَثَكَ قَالَ فَذَرْنِي حَتَّى أَمُوتَ ثُمَّ أُبْعَثَ فَسَوْفَ أُوتَى مَالًا وَوَلَدًا فَأَقْضِيكَ فَنَزَلَتْ هَذِهِ الْآيَةُ{ أَفَرَأَيْتَ الَّذِي كَفَرَ بِآيَاتِنَا وَقَالَ لَأُوتَيَنَّ مَالًا وَوَلَدًا }","trj":"Telah menceritakan kepada kami [Bisyr bin Khalid] Telah menceritakan kepada kami [Muhammad bin Ja'far] Telah menceritakan kepada kami [Syu'bah] dari [Sulaiman] Aku mendengar [Abu Adl Dluha] bercerita dari [Masruq] dari [Khabbab] dia berkata; \"Pada masa Jahiliyah aku adalah seorang pandai besi, dan Al Ash bin Wa'il mempunyai hutang kepadaku. Khabab berkata; maka aku datang kepadanya untuk menagihnya, namun dia berkata; \"Aku tidak akan membayarkannya sampai kamu mendustakan Muhammad.\" Khabab berkata; \"Demi Allah, aku tidak akan mendustakan Muhammad shallallahu 'alaihi wasallam sampai kamu dimatikan Allah kemudian kamu dibangkitkan kembali.\" Al Ash bin Wa`il berkata; \"Kalau begitu tunggulah sampai aku mati dan dibangkitkan kembali hingga aku diberi harta dan anak, maka aku akan membayarmu. Maka turunlah ayat ini: 'Maka apakah kamu Telah melihat orang yang kafir kepada ayat-ayat kami dan ia mengatakan: \"Pasti Aku akan diberi harta dan anak. (QS. Maryam: 77)."},{"p":"Bukhari","n":4061,"ar":"حَدَّثَنَا يَحْيَى حَدَّثَنَا وَكِيعٌ عَنْ الْأَعْمَشِ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ عَنْ خَبَّابٍ قَالَكُنْتُ رَجُلًا قَيْنًا وَكَانَ لِي عَلَى الْعَاصِ بْنِ وَائِلٍ دَيْنٌ فَأَتَيْتُهُ أَتَقَاضَاهُ فَقَالَ لِي لَا أَقْضِيكَ حَتَّى تَكْفُرَ بِمُحَمَّدٍ قَالَ قُلْتُ لَنْ أَكْفُرَ بِهِ حَتَّى تَمُوتَ ثُمَّ تُبْعَثَ قَالَ وَإِنِّي لَمَبْعُوثٌ مِنْ بَعْدِ الْمَوْتِ فَسَوْفَ أَقْضِيكَ إِذَا رَجَعْتُ إِلَى مَالٍ وَوَلَدٍ قَالَ فَنَزَلَتْ{ أَفَرَأَيْتَ الَّذِي كَفَرَ بِآيَاتِنَا وَقَالَ لَأُوتَيَنَّ مَالًا وَوَلَدًا أَطَّلَعَ الْغَيْبَ أَمْ اتَّخَذَ عِنْدَ الرَّحْمَنِ عَهْدًا كَلَّا سَنَكْتُبُ مَا يَقُولُ وَنَمُدُّ لَهُ مِنْ الْعَذَابِ مَدًّا وَنَرِثُهُ مَا يَقُولُ وَيَأْتِينَا فَرْدًا }","trj":"Telah menceritakan kepada kami [Yahya] Telah menceritakan kepada kami [Waki'] dari [Al A'masy] dari [Abu Adl Dluha] dari [Masruq] dari [Khabbab] dia berkata; \"Aku adalah seorang pandai besi yang bekerja untuk Al Ash bin Wa'il, ketika aku datang untuk menagih gajiku, dia berkata; \"Tidak, demi Allah aku tidak akan membayarkannya sampai kamu mendustakan Muhammad.\" Khabab berkata; \"Demi Allah, aku tidak akan mendustakan Muhammad shallallahu 'alaihi wasallam sampai kamu mati kemudian kamu dibangkitkan kembali.\" Al Ash bin Wa`il berkata; \"Apabila aku mati dan dibangkitkan serta dapat kembali kepada harta dan anakku, maka baru aku akan membayarmu!\" Khabbab berkata; maka turunlah ayat: 'Maka apakah kamu Telah melihat orang yang kafir kepada ayat-ayat kami dan ia mengatakan: \"Pasti Aku akan diberi harta dan anak. Adakah ia melihat yang ghaib atau ia telah membuat perjanjian di sisi Tuhan Yang Maha Pemurah? sekali-kali tidak, Kami akan menulis apa yang ia katakan, dan benar-benar Kami akan memperpanjang azab untuknya, dan Kami akan mewarisi apa yang ia katakan itu, dan ia akan datang kepada Kami dengan seorang diri. (QS. Maryam: 77-80)."},{"p":"Bukhari","n":6546,"ar":"حَدَّثَنَا خَلَّادُ بْنُ يَحْيَى حَدَّثَنَا عُمَرُ بْنُ ذَرٍّ سَمِعْتُ أَبِي يُحَدِّثُ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَا جِبْرِيلُ مَا يَمْنَعُكَ أَنْ تَزُورَنَا أَكْثَرَ مِمَّا تَزُورُنَا فَنَزَلَتْ{ وَمَا نَتَنَزَّلُ إِلَّا بِأَمْرِ رَبِّكَ لَهُ مَا بَيْنَ أَيْدِينَا وَمَا خَلْفَنَا }إِلَى آخِرِ الْآيَةِ قَالَ كَانَ هَذَا الْجَوَابَ لِمُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","trj":"Telah menceritakan kepada kami [Khallad bin Yahya] telah menceritakan kepada kami [Umar bin Dzar] aku mendengar [Ayahku] menceritakan dari [Said bin Jubair] dari [Ibn Abbas] Radliyallahu'anhuma, bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Wahai Jibril, apa yang menghalangimu untuk mengunjungi kami lebih sering daripada apa yang telah engkau lakukan?\" Maka turunlah ayat: '(Dan tidaklah Kami menurunkan ayat melainkan dengan perintah Tuhanmu, milik Dialah apa yang didepan kami dan di belakang kami) ', hingga akhir ayat (Qs. Maryam: 64). Dan jawaban ini adalah untuk Muhammad shallallahu 'alaihi wasallam.\""},{"p":"Ibnu Majah","n":4231,"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرٍ عَنْ أُمِّ مُبَشِّرٍ عَنْ حَفْصَةَ قَالَتْقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي لَأَرْجُو أَلَّا يَدْخُلَ النَّارَ أَحَدٌ إِنْ شَاءَ اللَّهُ تَعَالَى مِمَّنْ شَهِدَ بَدْرًا وَالْحُدَيْبِيَةَ قَالَتْ قُلْتُ يَا رَسُولَ اللَّهِ أَلَيْسَ قَدْ قَالَ اللَّهُ{ وَإِنْ مِنْكُمْ إِلَّا وَارِدُهَا كَانَ عَلَى رَبِّكَ حَتْمًا مَقْضِيًّا }قَالَ أَلَمْ تَسْمَعِيهِ يَقُولُ{ ثُمَّ نُنَجِّي الَّذِينَ اتَّقَوْا وَنَذَرُ الظَّالِمِينَ فِيهَا جِثِيًّا }","trj":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abu Mu'awiyah] dari [Aal A'masy] dari [Sufyan] dari [Jabir] dari [Ummu Mubasyir] dari [Hafshah] dia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya saya berharap tidak ada seorang pun dari kalangan orang-orang yang ikut serta dalam perang Badar dan Hudaibiyyah yang masuk neraka, Insya Allah Ta'ala.\" Hafshah berkata; Saya bertanya; \"Wahai Rasulullah, tidakkah Allah telah berfirman: \"Dan tidak ada seorangpun dari padamu, melainkan mendatangi neraka itu. hal itu bagi Tuhanmu adalah suatu kemestian yang sudah ditetapkan? (QS Maryam; 71).\" beliau bersabda: \"Apakah kamu tidak mendengar bahwa Dia juga berfirman: \"Kemudian kami akan menyelamatkan orang-orang yang bertakwa dan membiarkan orang-orang yang zalim di dalam neraka dalam keadaan berlutut.\" (QS Maryam; 72)."}]};
